/** 語言代碼 → 顯示標籤（找不到就傳回代碼本身） */
function langLabel(code) {
    if (!code) return '—';
    const opt = LANG_OPTIONS.find(o => o.code.toLowerCase() === code.toLowerCase());
    return opt ? opt.label : code;
}

function countWords(text) {
    if (!text) return 0;
    let count = 0;
    const cjk = text.match(/[\u4e00-\u9fff\u3400-\u4dbf\uf900-\ufaff]/g);
    if (cjk) count += cjk.length;
    const cleaned = text.replace(/[\u4e00-\u9fff\u3400-\u4dbf\uf900-\ufaff]/g, ' ');
    const words = cleaned.trim().split(/\s+/).filter(w => w.length > 0);
    count += words.length;
    return count;
}

/** 渲染語言代碼為 badge HTML（供 innerHTML 插入） */
function langBadgeHtml(codes, dir = '') {
    if (!codes || !codes.length) return '<span style="color:#94a3b8; font-size:0.8rem;">—</span>';
    const badges = codes.map(c =>
        `<span style="display:inline-block; background:#e0f2fe; color:#0369a1; border-radius:4px; padding:1px 6px; font-size:0.78rem; white-space:nowrap; font-family:monospace;">${c.toUpperCase()}</span>`
    ).join(' ');
    return dir ? `<span style="color:#94a3b8; font-size:0.75rem;">${dir}</span> ${badges}` : badges;
}

/** 建立語言多選 UI（checkbox 列表），回傳 container element
 *  @param {string[]} selected - 已選中的語言代碼
 */
function buildLangCheckboxes(selected = []) {
    const wrap = document.createElement('div');

    // 搜尋框
    const search = document.createElement('input');
    search.type = 'text';
    search.placeholder = '搜尋語言…';
    search.autocomplete = 'off';
    search.style.cssText = 'width:100%; box-sizing:border-box; padding:0.3rem 0.5rem; margin-bottom:0.3rem; border:1px solid #cbd5e1; border-radius:5px; font-size:0.82rem;';
    wrap.appendChild(search);

    // Checkbox 容器
    const container = document.createElement('div');
    container.style.cssText = 'display:flex; flex-wrap:wrap; gap:0.35rem; max-height:160px; overflow-y:auto; padding:0.25rem; border:1px solid #e2e8f0; border-radius:6px; background:#f8fafc;';
    LANG_OPTIONS.forEach(opt => {
        const lbl = document.createElement('label');
        lbl.style.cssText = 'display:inline-flex; align-items:center; gap:0.25rem; cursor:pointer; padding:0.2rem 0.4rem; border-radius:4px; font-size:0.82rem; white-space:nowrap; background:#fff; border:1px solid #e2e8f0;';
        const cb = document.createElement('input');
        cb.type = 'checkbox';
        cb.value = opt.code;
        cb.checked = selected.includes(opt.code);
        cb.style.cursor = 'pointer';
        lbl.appendChild(cb);
        lbl.appendChild(document.createTextNode(opt.label));
        container.appendChild(lbl);
    });
    wrap.appendChild(container);

    // 即時搜尋過濾
    search.addEventListener('input', () => {
        const q = search.value.toLowerCase();
        container.querySelectorAll('label').forEach(lbl => {
            lbl.style.display = lbl.textContent.toLowerCase().includes(q) ? '' : 'none';
        });
    });

    return wrap;
}

/** 從 buildLangCheckboxes 回傳的 container 取得已勾選的代碼陣列 */
function getCheckedLangs(container) {
    return Array.from(container.querySelectorAll('input[type=checkbox]:checked')).map(cb => cb.value);
}

/**
 * 頁內通用確認（取代 window.confirm）。message 建議為「是否確定要……？」完整句。
 * 預設不顯示標題列；若需標題可傳 options.title（非空字串）。
 * @param {string} message
 * @param {{ title?: string }} [options]
 * @returns {Promise<boolean>}
 */
function openCatConfirmModal(message, options = {}) {
    const rawTitle = options.title != null ? String(options.title) : '';
    const title = rawTitle.trim();
    return new Promise((resolve) => {
        const modal = document.getElementById('catGenericConfirmModal');
        const titleEl = document.getElementById('catGenericConfirmTitle');
        const msgEl = document.getElementById('catGenericConfirmMsg');
        const btnOk = document.getElementById('btnCatGenericConfirmOk');
        const btnCancel = document.getElementById('btnCatGenericConfirmCancel');
        if (!modal || !titleEl || !msgEl || !btnOk || !btnCancel) {
            resolve(window.confirm(message));
            return;
        }
        let settled = false;
        if (title) {
            titleEl.textContent = title;
            titleEl.classList.remove('hidden');
            titleEl.removeAttribute('aria-hidden');
        } else {
            titleEl.textContent = '';
            titleEl.classList.add('hidden');
            titleEl.setAttribute('aria-hidden', 'true');
        }
        msgEl.textContent = message;
        function cleanup() {
            modal.classList.add('hidden');
            btnOk.removeEventListener('click', onOk);
            btnCancel.removeEventListener('click', onCancel);
            modal.removeEventListener('click', onOverlay);
            document.removeEventListener('keydown', onKey);
        }
        function finish(v) {
            if (settled) return;
            settled = true;
            cleanup();
            resolve(v);
        }
        function onOk() { finish(true); }
        function onCancel() { finish(false); }
        function onOverlay(e) {
            if (e.target === modal) onCancel();
        }
        function onKey(e) {
            if (e.key === 'Escape' && !modal.classList.contains('hidden')) {
                e.preventDefault();
                onCancel();
            }
        }
        btnOk.addEventListener('click', onOk);
        btnCancel.addEventListener('click', onCancel);
        modal.addEventListener('click', onOverlay);
        document.addEventListener('keydown', onKey);
        modal.classList.remove('hidden');
    });
}

/**
 * 批次／單檔 XLIFF 匯入完成後：原始檔語言對與任務語言對不符之統一提示（原生 dialog；清單過長可捲動）。
 * @param {{ fileName: string, originalSourceLang: string, originalTargetLang: string }[]} rows
 * @param {{ sourceLang: string, targetLang: string }} langChoice
 * @returns {Promise<void>}
 */
function openBatchImportLangMismatchDialog(rows, langChoice) {
    return new Promise((resolve) => {
        const dlg = document.getElementById('batchImportLangMismatchDialog');
        const list = document.getElementById('batchImportLangMismatchList');
        const pairEl = document.getElementById('batchImportLangMismatchTaskPair');
        if (!rows || !rows.length) {
            resolve();
            return;
        }
        const taskSrc = (langChoice && langChoice.sourceLang) || '—';
        const taskTgt = (langChoice && langChoice.targetLang) || '—';
        const fallbackMsg = [
            `以下 ${rows.length} 個檔案之原始語言對與任務設定不符（檔案已成功匯入）。`,
            '',
            `本次任務語言對：${taskSrc} → ${taskTgt}`,
            '',
            ...rows.map((r) => `• ${r.fileName}：原始 ${r.originalSourceLang || '—'} → ${r.originalTargetLang || '—'}`),
            '',
            '系統將以任務設定為準進行 TM／TB 比對與寫入；匯出時原始語言對會從原始檔案還原，不受影響。'
        ].join('\n');
        if (!dlg || !list || !pairEl) {
            void openCatConfirmModal(fallbackMsg, { title: '語言對不符' }).then(() => resolve());
            return;
        }
        pairEl.textContent = `${taskSrc} → ${taskTgt}`;
        list.innerHTML = '';
        rows.forEach((r) => {
            const li = document.createElement('li');
            li.style.marginBottom = '0.55rem';
            li.textContent = `${r.fileName}：原始 ${r.originalSourceLang || '—'} → ${r.originalTargetLang || '—'}`;
            list.appendChild(li);
        });
        let settled = false;
        function finish() {
            if (settled) return;
            settled = true;
            dlg.removeEventListener('close', onClose);
            resolve();
        }
        function onClose() { finish(); }
        dlg.addEventListener('close', onClose);
        try {
            if (typeof dlg.showModal === 'function') dlg.showModal();
            else throw new Error('no showModal');
        } catch (_) {
            dlg.removeEventListener('close', onClose);
            void openCatConfirmModal(fallbackMsg, { title: '語言對不符' }).then(() => resolve());
        }
    });
}

/**
 * 頁內通用單行輸入（取代 window.prompt）。
 * @param {{ title?: string, label?: string, defaultValue?: string }} [options]
 * @returns {Promise<string|null>} 確定時為 trim 後字串；取消為 null
 */
function openCatPromptModal(options = {}) {
    const title = options.title != null ? String(options.title) : '輸入';
    const label = options.label != null ? String(options.label) : '請輸入：';
    const defaultValue = options.defaultValue != null ? String(options.defaultValue) : '';
    return new Promise((resolve) => {
        const modal = document.getElementById('catGenericPromptModal');
        const titleEl = document.getElementById('catGenericPromptTitle');
        const labelEl = document.getElementById('catGenericPromptLabel');
        const inputEl = document.getElementById('catGenericPromptInput');
        const btnOk = document.getElementById('btnCatGenericPromptOk');
        const btnCancel = document.getElementById('btnCatGenericPromptCancel');
        if (!modal || !titleEl || !labelEl || !inputEl || !btnOk || !btnCancel) {
            const v = window.prompt(label, defaultValue);
            resolve(v === null ? null : String(v));
            return;
        }
        let settled = false;
        titleEl.textContent = title;
        labelEl.textContent = label;
        inputEl.value = defaultValue;
        function cleanup() {
            modal.classList.add('hidden');
            btnOk.removeEventListener('click', onOk);
            btnCancel.removeEventListener('click', onCancel);
            modal.removeEventListener('click', onOverlay);
            document.removeEventListener('keydown', onKey);
        }
        function finish(v) {
            if (settled) return;
            settled = true;
            cleanup();
            resolve(v);
        }
        function onOk() {
            finish(inputEl.value);
        }
        function onCancel() {
            finish(null);
        }
        function onOverlay(e) {
            if (e.target === modal) onCancel();
        }
        function onKey(e) {
            if (e.key === 'Escape' && !modal.classList.contains('hidden')) {
                e.preventDefault();
                onCancel();
            }
        }
        btnOk.addEventListener('click', onOk);
        btnCancel.addEventListener('click', onCancel);
        modal.addEventListener('click', onOverlay);
        document.addEventListener('keydown', onKey);
        modal.classList.remove('hidden');
        requestAnimationFrame(() => {
            inputEl.focus();
            inputEl.select();
        });
    });
}

/**
 * 在自製多選標籤下拉底部加上「+ 新增標籤」；點擊後寫入 DB 並呼叫 onAfterAdd(name)。
 * @param {HTMLElement | null} dropdownEl
 * @param {(addedName: string) => void | Promise<void>} [onAfterAdd]
 */
function _appendAiMultiselectAddTagButton(dropdownEl, onAfterAdd) {
    if (!dropdownEl) return;
    const prev = dropdownEl.querySelector('[data-cat-tag-add-new="1"]');
    if (prev) prev.remove();
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.setAttribute('data-cat-tag-add-new', '1');
    btn.className = 'ai-multiselect-add-new-row';
    btn.textContent = '+ 新增標籤';
    btn.addEventListener('click', async (e) => {
        e.preventDefault();
        e.stopPropagation();
        const raw = await openCatPromptModal({ title: '新增標籤', label: '標籤名稱', defaultValue: '' });
        const name = raw != null ? String(raw).trim() : '';
        if (!name) return;
        try {
            await DBService.addAiCategoryTag(name);
        } catch (err) {
            alert('無法新增標籤：' + (err && err.message ? err.message : String(err)));
            return;
        }
        if (typeof onAfterAdd === 'function') {
            await onAfterAdd(name);
        }
    });
    dropdownEl.appendChild(btn);
}

/**
 * 自製下拉範本：同步浮層 hidden 與觸發列 `ai-multiselect-trigger--open`（類別標籤、互斥群組等共用）。
 * @param {HTMLElement | null} triggerEl
 * @param {HTMLElement | null} panelEl
 * @param {boolean} isOpen  true = 展開
 */
function catSetDropdownPanelOpen(triggerEl, panelEl, isOpen) {
    if (panelEl) panelEl.classList.toggle('hidden', !isOpen);
    if (triggerEl && triggerEl.classList) triggerEl.classList.toggle('ai-multiselect-trigger--open', !!isOpen);
}
window.catSetDropdownPanelOpen = catSetDropdownPanelOpen;

