    function _scFormat(sc) {
        const parts = [];
        if (sc.ctrl) parts.push('Ctrl');
        if (sc.alt) parts.push('Alt');
        if (sc.shift) parts.push('Shift');
        parts.push(sc.key.toUpperCase());
        return parts.join(' + ');
    }

    /** 與 keydown 實際綁定一致之顯示字串（單一真相，供按鈕 title 與快捷鍵 modal 灌入） */
    const FIXED_SHORTCUT_LABELS = {
        copySourceToTarget: 'Ctrl + Insert',
        clearTarget: 'Ctrl + Shift + Insert',
        segNavUpDown: 'Ctrl + ↑ / ↓',
        catListNav: 'Alt + ↑ / ↓',
        catResultPage: 'Alt + ← / →',
        rightPanelTab: 'Ctrl + Alt + ← / →',
        fakeCaretFocus: 'Ctrl + Alt + ↑ / ↓'
    };

    function refreshFixedShortcutTitles() {
        const L = FIXED_SHORTCUT_LABELS;
        const btnCopy = document.getElementById('btnCopySourceToTarget');
        if (btnCopy) {
            btnCopy.setAttribute('title', `將原文複製到譯文 (${L.copySourceToTarget})\n支援批次：選取多個句段後點擊`);
        }
        const btnClear = document.getElementById('btnClearTarget');
        if (btnClear) {
            btnClear.setAttribute('title', `清除譯文 (${L.clearTarget})\n支援批次：選取多個句段後點擊`);
        }
        const map = [
            ['scFixedKeySegNav', 'segNavUpDown'],
            ['scFixedKeyClearTarget', 'clearTarget'],
            ['scFixedKeyCopySource', 'copySourceToTarget'],
            ['scFixedKeyCatList', 'catListNav'],
            ['scFixedKeyCatPage', 'catResultPage'],
            ['scFixedKeyRightTab', 'rightPanelTab'],
            ['scFixedKeyFakeCaret', 'fakeCaretFocus']
        ];
        for (const [id, k] of map) {
            const el = document.getElementById(id);
            if (el && L[k]) el.value = L[k];
        }
    }

    function loadCustomShortcuts() {
        try {
            const raw = localStorage.getItem(CUSTOM_SC_KEY);
            return raw ? JSON.parse(raw) : {};
        } catch (_) { return {}; }
    }

    function saveCustomShortcut(id, sc) {
        const data = loadCustomShortcuts();
        data[id] = sc;
        localStorage.setItem(CUSTOM_SC_KEY, JSON.stringify(data));
    }

    function getCustomShortcut(id) {
        const data = loadCustomShortcuts();
        const def = CUSTOM_SC_DEFS.find(d => d.id === id);
        return data[id] || (def && def.def) || null;
    }

    function renderCustomShortcutRows() {
        const container = document.getElementById('customShortcutRows');
        if (!container) return;
        container.innerHTML = '';
        // 使用 CSS Grid 讓標籤欄和 key input 欄寬度對齊
        container.style.cssText = 'display:grid; grid-template-columns:1fr minmax(108px,130px) auto; gap:0.5rem 0.75rem; align-items:start;';
        CUSTOM_SC_DEFS.forEach(def => {
            const sc = getCustomShortcut(def.id);
            const labelWrap = document.createElement('div');
            labelWrap.className = 'sc-custom-label-wrap';
            const label = document.createElement('span');
            label.textContent = def.label;
            labelWrap.appendChild(label);
            if (def.desc) {
                const p = document.createElement('p');
                p.className = 'sc-custom-desc';
                p.textContent = def.desc;
                labelWrap.appendChild(p);
            }
            const keyInput = document.createElement('input');
            keyInput.type = 'text';
            keyInput.value = _scFormat(sc);
            keyInput.readOnly = true;
            keyInput.className = 'sc-key-input sc-custom-input';
            keyInput.style.cssText = 'width:100%; cursor:default;';
            const recordBtn = document.createElement('button');
            recordBtn.type = 'button';
            recordBtn.className = 'secondary-btn btn-sm';
            recordBtn.textContent = '錄製';
            recordBtn.style.flexShrink = '0';
            recordBtn.addEventListener('click', () => {
                if (keyInput.classList.contains('sc-recording-active')) return;
                const prevH = keyInput._scRecordKeydownHandler;
                if (prevH) document.removeEventListener('keydown', prevH, true);
                keyInput.classList.add('sc-recording-active');
                keyInput.value = '等待按鍵…';
                const handler = (e) => {
                    if (e.key === 'Escape') {
                        e.preventDefault();
                        e.stopPropagation();
                        keyInput.value = _scFormat(getCustomShortcut(def.id));
                        keyInput.classList.remove('sc-recording-active');
                        document.removeEventListener('keydown', handler, true);
                        keyInput._scRecordKeydownHandler = undefined;
                        return;
                    }
                    const modOnly = ['Control','Alt','Shift','Meta'].includes(e.key);
                    if (modOnly) return;
                    e.preventDefault();
                    e.stopPropagation();
                    const newSc = { ctrl: e.ctrlKey, alt: e.altKey, shift: e.shiftKey, key: e.key.length === 1 ? e.key.toLowerCase() : e.key };
                    saveCustomShortcut(def.id, newSc);
                    keyInput.value = _scFormat(newSc);
                    keyInput.classList.remove('sc-recording-active');
                    document.removeEventListener('keydown', handler, true);
                    keyInput._scRecordKeydownHandler = undefined;
                };
                keyInput._scRecordKeydownHandler = handler;
                document.addEventListener('keydown', handler, true);
            });
            const resetBtn = document.createElement('button');
            resetBtn.type = 'button';
            resetBtn.className = 'secondary-btn btn-sm';
            resetBtn.textContent = '重設';
            resetBtn.style.flexShrink = '0';
            resetBtn.addEventListener('click', () => {
                const h = keyInput._scRecordKeydownHandler;
                if (h) document.removeEventListener('keydown', h, true);
                keyInput._scRecordKeydownHandler = undefined;
                const data = loadCustomShortcuts();
                delete data[def.id];
                localStorage.setItem(CUSTOM_SC_KEY, JSON.stringify(data));
                keyInput.value = _scFormat(def.def);
                keyInput.classList.remove('sc-recording-active');
            });
            const btns = document.createElement('div');
            btns.style.cssText = 'display:flex; gap:0.3rem; flex-shrink:0;';
            btns.append(recordBtn, resetBtn);
            container.append(labelWrap, keyInput, btns);
        });
    }
    
