    /** Esc：關閉最上層蓋版（等同取消／關閉鈕）；錄製自訂快捷鍵時 Esc 由錄製 handler 中止、不關視窗 */
    (function setupCatGlobalModalEscape() {
        const ESC_BUTTON_BY_OVERLAY_ID = {
            exportTagWarningModal: 'exportTagWarningCancel',
            noteSharingModal: 'btnNoteSharingCancel',
            privateNoteShareModal: 'btnPrivateNoteShareCancel',
            sfPresetManagerModal: 'btnCloseSfPresetManager',
            aiBatchAskModal: 'btnBatchAskCancel',
            aiReviewModal: 'btnSkipAiReview',
            aiGuidelinePickerModal: 'btnCloseAiGuidelinePicker',
            agMutexJoinModal: 'btnAgMutexJoinCancel',
            agIssueJoinModal: 'btnAgIssueJoinCancel',
            agEditGuidelineModal: 'btnAgEditGuidelineCancel',
            pgEditProjectGuidelineModal: 'btnPgEditProjectGuidelineCancel',
            pgManageProjectGuidelinesModal: 'btnPgManageProjectGuidelinesClose',
            aiScanModal: 'btnCancelAiScan',
            aiScanConfirmModal: 'btnCancelAiScanConfirm',
            remoteConflictModal: 'btnRemoteConflictCancel',
            qaFilterScopeConfirmModal: 'btnQaFilterScopeConfirmCancel',
            tmsProfileCard: 'btnCloseTmsProfileCard',
            namingModal: 'btnCloseNamingModalFooter',
            exportResourceModal: 'btnCancelExportResource',
            projectTmPickerModal: 'btnProjectTmPickerCancel',
            projectTbPickerModal: 'btnProjectTbPickerCancel',
            tbExcelImportModal: 'btnCancelTbExcelImport',
            preTranslateModal: 'btnCancelPreTranslate',
            fileAssignModal: 'btnCancelFileAssign',
            aiBatchModal: 'btnCancelAiBatch',
            tbTermEditModal: 'btnCancelTbTermEdit',
            highMatchGuardModal: 'btnHighMatchGuardCancel',
        };
        function parseZ(el) {
            const z = parseInt(getComputedStyle(el).zIndex, 10);
            return Number.isFinite(z) ? z : 0;
        }
        function collectVisibleModalRoots() {
            const roots = [];
            document.querySelectorAll('.wizard-overlay:not(.hidden), .modal-overlay:not(.hidden)').forEach((el) => { roots.push(el); });
            const tms = document.getElementById('tmsProfileCard');
            if (tms && getComputedStyle(tms).display !== 'none') roots.push(tms);
            return roots;
        }
        function topModalRoot(roots) {
            if (!roots.length) return null;
            return roots.reduce((best, el) => {
                const zb = parseZ(best);
                const ze = parseZ(el);
                if (ze > zb) return el;
                if (ze < zb) return best;
                return (best.compareDocumentPosition(el) & Node.DOCUMENT_POSITION_FOLLOWING) ? el : best;
            });
        }
        function findEscDismissControl(overlay) {
            if (!overlay || !overlay.id) return null;
            const mapped = ESC_BUTTON_BY_OVERLAY_ID[overlay.id];
            if (mapped) {
                const b = document.getElementById(mapped);
                if (b && overlay.contains(b)) return b;
            }
            const attr = overlay.querySelector('[data-cat-esc-dismiss]');
            if (attr) return attr;
            const close = overlay.querySelector('button.close-btn');
            if (close) return close;
            const foot = overlay.querySelector('.panel-footer');
            if (foot) {
                const sec = foot.querySelector('button.secondary-btn');
                if (sec) return sec;
            }
            return null;
        }
        document.addEventListener('keydown', (e) => {
            if (e.key !== 'Escape') return;
            const sm = document.getElementById('shortcutsModal');
            if (sm && !sm.classList.contains('hidden') && sm.querySelector('.sc-custom-input.sc-recording-active')) return;
            const roots = collectVisibleModalRoots();
            const top = topModalRoot(roots);
            if (!top) return;
            const btn = findEscDismissControl(top);
            e.preventDefault();
            e.stopPropagation();
            if (btn) btn.click();
            else top.classList.add('hidden');
        }, true);
    })();

    // ---- 將原文複製到譯文 / 清除譯文（單一 + 批次）----

    /**
     * 對指定 segment 套用操作（'copy-source' 或 'clear'），同步更新 DOM 與 DB。
     * - copy-source：同步複製 sourceText 與 sourceTags
     * - clear：清除 targetText 及 targetTags
     */
    /**
     * 同一句 `applyUpdateSegmentTarget` 串行化（Phase A），避免 debounce 與確認等路徑並行帶同一預期 revision。
     * Map 值為「尾端 Promise」，成功或失敗皆須前進鏈結，故以 `.then(()=>{},()=>{})` 吞錯接續。
     */
    const segmentTargetWriteTails = new Map();

    /** 確認寫庫前 await：與 debounce 已啟動、無法被 clearTimeout 取消的寫庫銜接（Phase B）。 */
    function awaitPendingSegmentTargetWritesForSeg(segId) {
        if (segId == null) return Promise.resolve();
        const t = segmentTargetWriteTails.get(String(segId));
        return t || Promise.resolve();
    }

    /** 團隊模式 revision 衝突後自 DB 回填 `seg.segmentRevision`（Phase C 重試前）。 */
    async function hydrateSegmentRevisionFromDb(seg) {
        if (!currentFileId || !seg || seg.id == null) return false;
        try {
            const all = await DBService.getSegmentsByFile(currentFileId);
            const fresh = Array.isArray(all) ? all.find(s => String(s.id) === String(seg.id)) : null;
            if (!fresh) return false;
            if (typeof fresh.segmentRevision === 'number' && !Number.isNaN(fresh.segmentRevision)) {
                seg.segmentRevision = fresh.segmentRevision;
            }
            return true;
        } catch (e) {
            console.error('[cat-revision] hydrate revision failed', e, seg.id);
            return false;
        }
    }

    /**
     * Team 雲端寫庫帶 `segmentRevision` 樂觀鎖；成功回寫 `seg.segmentRevision`。
     * 衝突時擲出 `code === 'SEGMENT_REVISION_CONFLICT'`（debounce 可靜默丟棄）。
     * 團隊模式 revision 衝突時會自 DB 刷新 revision 後重試一次（Phase C）。
     */
    async function applyUpdateSegmentTarget(seg, newText, extra = {}) {
        const ex = extra == null || typeof extra !== 'object' ? {} : extra;
        const key = String(seg.id);
        const prev = segmentTargetWriteTails.get(key) || Promise.resolve();

        const run = async () => {
            const doRpc = async () => {
                const r = await DBService.updateSegmentTarget(
                    seg.id,
                    newText,
                    ex,
                    seg.segmentRevision != null && seg.segmentRevision !== undefined ? Number(seg.segmentRevision) : 0
                );
                if (r && r.conflict) {
                    if (isCatCollabDebug()) {
                        console.info('[cat-revision] SEGMENT_REVISION_CONFLICT', {
                            segId: seg.id,
                            expectedRevision: seg.segmentRevision != null && seg.segmentRevision !== undefined ? Number(seg.segmentRevision) : 0
                        });
                    }
                    const err = new Error('segment revision conflict');
                    err.code = 'SEGMENT_REVISION_CONFLICT';
                    throw err;
                }
                if (r && typeof r.newSegmentRevision === 'number' && !Number.isNaN(r.newSegmentRevision)) {
                    seg.segmentRevision = r.newSegmentRevision;
                } else if (isCatCollabDebug() && r && r.conflict !== true) {
                    console.warn('[cat-revision] update ok but missing newSegmentRevision', { segId: seg.id, r });
                }
                if (isCatCollabDebug() && r && r.conflict !== true) {
                    console.info('[cat-revision] ok', { segId: seg.id, segmentRevision: seg.segmentRevision });
                }
                return r;
            };

            try {
                return await doRpc();
            } catch (err) {
                if (err && err.code === 'SEGMENT_REVISION_CONFLICT' && isTeamMode()) {
                    const ok = await hydrateSegmentRevisionFromDb(seg);
                    if (ok) {
                        return await doRpc();
                    }
                }
                throw err;
            }
        };

        const p = prev.then(() => run());
        segmentTargetWriteTails.set(key, p.then(() => {}, () => {}));
        return p;
    }
    async function applySegmentTextOp(seg, rowEl, op) {
        if (!seg || isTargetWriteProtected(seg)) return;
        markEmptySegUserEdited(seg.id);

        const newText = op === 'copy-source' ? seg.sourceText : '';
        if (op === 'copy-source') {
            seg.targetTags = (seg.sourceTags || []).map(t => ({ ...t }));
        } else {
            seg.targetTags = [];
            seg.matchValue = undefined;
        }
        seg.targetText = newText;

        if (rowEl) {
            const editor = rowEl.querySelector('.grid-textarea');
            if (editor) {
                setEditorHtml(editor, buildTaggedHtml(newText, effectiveTags(seg)));
                updateTagColors(rowEl, newText);
            }
            if (op === 'clear') applyMatchCellVisual(rowEl, '');
            if (seg.status === 'confirmed') {
                seg.status = 'unconfirmed';
                const si = rowEl.querySelector('.status-icon');
                if (si) si.classList.remove('done');
                rowEl.style.backgroundColor = '';
                await DBService.updateSegmentStatus(seg.id, 'unconfirmed');
            }
        }
        const extra = { targetTags: seg.targetTags };
        if (op === 'clear') extra.matchValue = '';
        await applyUpdateSegmentTarget(seg, newText, extra);
    }

    async function runTextOpOnSelection(op) {
        const targetIds = new Set(selectedRowIds);
        isBatchOpInProgress = true;
        let deferBatchClear = false;
        try {
            if (targetIds.size > 0) {
                const items = [];
                const pending = [];
                for (const seg of currentSegmentsList) {
                    if (targetIds.has(seg.id)) {
                        if (isTargetWriteProtected(seg)) continue;
                        const rowEl = gridBody ? gridBody.querySelector(`.grid-data-row[data-seg-id="${seg.id}"]`) : document.querySelector(`.grid-data-row[data-seg-id="${seg.id}"]`);
                        if (!isGridDataRowFilterVisible(rowEl)) continue;
                        const beforeSnap = snapshotSegForUndo(seg);
                        markEmptySegUserEdited(seg.id);
                        const newText = op === 'copy-source' ? seg.sourceText : '';
                        if (op === 'copy-source') {
                            seg.targetTags = (seg.sourceTags || []).map(t => ({ ...t }));
                        } else {
                            seg.targetTags = [];
                            seg.matchValue = undefined;
                        }
                        seg.targetText = newText;
                        if (rowEl) {
                            const editor = rowEl.querySelector('.grid-textarea');
                            if (editor) {
                                setEditorHtml(editor, buildTaggedHtml(newText, effectiveTags(seg)));
                                updateTagColors(rowEl, newText);
                            }
                            if (op === 'clear') applyMatchCellVisual(rowEl, '');
                            if (seg.status === 'confirmed') {
                                seg.status = 'unconfirmed';
                                const si = rowEl.querySelector('.status-icon');
                                if (si) si.classList.remove('done');
                                if (currentFileFormat === 'mqxliff' && si) si.innerHTML = '';
                                rowEl.style.backgroundColor = '';
                                pending.push(DBService.updateSegmentStatus(seg.id, 'unconfirmed'));
                            }
                        }
                        const extra = { targetTags: seg.targetTags };
                        if (op === 'clear') extra.matchValue = '';
                        pending.push(applyUpdateSegmentTarget(seg, newText, extra));
                        items.push({ id: seg.id, beforeSnap, afterSnap: snapshotSegForUndo(seg) });
                    }
                }
                if (items.length) pushUndoEntry({ kind: 'segmentState', items });
                updateProgress();
                deferBatchClear = true;
                void Promise.all(pending).catch((e) => console.error(e)).finally(() => { isBatchOpInProgress = false; });
                return;
            }
            const activeRow = gridBody ? gridBody.querySelector('.grid-data-row.active-row') : document.querySelector('.grid-data-row.active-row');
            if (!activeRow) return;
            const segId = parseId(activeRow.dataset.segId);
            const seg = currentSegmentsList.find(s => s.id === segId);
            const beforeSnap = snapshotSegForUndo(seg);
            await applySegmentTextOp(seg, activeRow, op);
            const afterSnap = snapshotSegForUndo(seg);
            if (JSON.stringify(beforeSnap) !== JSON.stringify(afterSnap)) {
                pushUndoEntry({ kind: 'segmentState', items: [{ id: seg.id, beforeSnap, afterSnap }] });
                editorUndoEditStart[seg.id] = afterSnap.targetText;
                editorUndoStatusStart[seg.id] = afterSnap.status;
                editorUndoMatchStart[seg.id] = afterSnap.matchValue;
            }
            updateProgress();
        } finally {
            if (!deferBatchClear) isBatchOpInProgress = false;
        }
    }

    const btnCopySourceToTarget = document.getElementById('btnCopySourceToTarget');
