    /** 掃描所有譯文 contenteditable，插入非列印字元標記 */
    function applyNonPrintMarkersAll() {
        const editorGrid = document.getElementById('editorGrid');
        if (!editorGrid || !editorGrid.classList.contains('show-non-print')) return;
        // 同時處理原文欄（.col-source .rt-editor）和譯文欄（.col-target .rt-editor）
        editorGrid.querySelectorAll('.col-source .rt-editor, .col-target .rt-editor').forEach(applyNonPrintMarkers);
    }

    /** 換行箭頭等 overlay span（不含空白類 np-inline-char）。 */
    function isNpOverlayMarker(el) {
        return !!(el && el.nodeType === 1 && el.classList && el.classList.contains('non-print-marker') && !el.classList.contains('np-inline-char'));
    }

    /**
     * 在 rt-editor 元素的文字節點中插入非列印字元標記 span。
     * 僅在 show-non-print 模式下有視覺效果（CSS 控制 display）。
     * 使用 data-np-applied 旗標防止重複插入。
     * ¶ 段落結束標記改由 CSS ::after 負責，此函數不再插入 DOM。
     */
    function applyNonPrintMarkers(el) {
        if (el.hasAttribute('data-np-applied')) return;
        el.setAttribute('data-np-applied', '1');
        // 標記 <br>（換行）
        el.querySelectorAll('br:not(.np-br)').forEach(br => {
            const mark = document.createElement('span');
            mark.className = 'non-print-marker';
            mark.textContent = '↵';
            mark.contentEditable = 'false';
            br.parentNode.insertBefore(mark, br);
            br.classList.add('np-br');
        });
        // 標記普通空格和 NBSP（文字節點）—— 跳過 non-print-marker 本身和標籤 chip
        const walker = document.createTreeWalker(el, NodeFilter.SHOW_TEXT, {
            acceptNode: n => {
                const p = n.parentElement;
                if (!p) return NodeFilter.FILTER_ACCEPT;
                if (p.classList.contains('non-print-marker')) return NodeFilter.FILTER_REJECT;
                if (p.classList.contains('rt-tag') || p.classList.contains('tag-num') || p.classList.contains('tag-content')) return NodeFilter.FILTER_REJECT;
                return NodeFilter.FILTER_ACCEPT;
            }
        });
        const textNodes = [];
        let node;
        while ((node = walker.nextNode())) textNodes.push(node);
        textNodes.forEach(tn => {
            if (!tn.textContent.match(/[ \t\u00A0\u200B\u3000]/)) return;
            const frag = document.createDocumentFragment();
            const parts = tn.textContent.split(/([ \t\u00A0\u200B\u3000])/);
            parts.forEach(part => {
                if (part === ' ' || part === '\t' || part === '\u00A0' || part === '\u200B' || part === '\u3000') {
                    const wrap = document.createElement('span');
                    wrap.className = 'non-print-marker np-inline-char';
                    wrap.setAttribute(
                        'data-np',
                        part === ' '
                            ? 'sp'
                            : part === '\t'
                              ? 'tab'
                              : part === '\u00A0'
                                ? 'nbsp'
                                : part === '\u3000'
                                  ? 'ideosp'
                                  : 'zwsp'
                    );
                    wrap.appendChild(document.createTextNode(part));
                    frag.appendChild(wrap);
                } else {
                    frag.appendChild(document.createTextNode(part));
                }
            });
            tn.parentNode.replaceChild(frag, tn);
        });
    }

    /**
     * 移除 el 內所有非列印字元標記 span 並合併相鄰文字節點，還原乾淨的 DOM。
     * 配合 refreshNonPrintMarkers 使用，確保重新套用時不會疊加舊標記。
     */
    function stripNonPrintMarkers(el) {
        el.querySelectorAll('br.np-br').forEach(br => br.classList.remove('np-br'));
        el.querySelectorAll('.np-inline-char').forEach(wrap => {
            const parent = wrap.parentNode;
            if (!parent) return;
            while (wrap.firstChild) parent.insertBefore(wrap.firstChild, wrap);
            wrap.remove();
        });
        el.querySelectorAll('.non-print-marker').forEach(m => m.remove());
        el.normalize();
    }

    /**
     * 清除舊標記後重新套用非列印字元標記（冪等，可對已套用過的元素重複呼叫）。
     * 非列印模式未開啟時為空操作。
     */
    function refreshNonPrintMarkers(el) {
        if (!el) return;
        if (!document.getElementById('editorGrid')?.classList.contains('show-non-print')) return;
        stripNonPrintMarkers(el);
        el.removeAttribute('data-np-applied');
        applyNonPrintMarkers(el);
    }

    /**
     * 以字元偏移量記錄游標位置（跳過非列印標記，BR 計為 1 字元）。
     * 用於 refreshNonPrintMarkers 前後保存/還原游標，避免游標跳位。
     */
    function getNpCaretOffset(el) {
        const sel = window.getSelection();
        if (!sel || !sel.rangeCount) return null;
        const r = sel.getRangeAt(0);
        if (!el.contains(r.startContainer)) return null;
        let offset = 0;
        const walker = document.createTreeWalker(el, NodeFilter.SHOW_ALL, {
            acceptNode: n => {
                if (n.nodeType === 1 && n.classList && n.classList.contains('non-print-marker') && !n.classList.contains('np-inline-char')) {
                    return NodeFilter.FILTER_REJECT;
                }
                return NodeFilter.FILTER_ACCEPT;
            }
        });
        let nd;
        while ((nd = walker.nextNode())) {
            if (nd === r.startContainer) { offset += r.startOffset; break; }
            if (nd.nodeType === 3) offset += nd.nodeValue.length;
            else if (nd.nodeType === 1 && nd.tagName === 'BR') offset += 1;
        }
        return offset;
    }

    /** 依字元偏移量還原游標位置（跳過非列印標記）。 */
    function setNpCaretOffset(el, targetOffset) {
        let remaining = targetOffset;
        const walker = document.createTreeWalker(el, NodeFilter.SHOW_ALL, {
            acceptNode: n => {
                if (n.nodeType === 1 && n.classList && n.classList.contains('non-print-marker') && !n.classList.contains('np-inline-char')) {
                    return NodeFilter.FILTER_REJECT;
                }
                return NodeFilter.FILTER_ACCEPT;
            }
        });
        let nd;
        while ((nd = walker.nextNode())) {
            if (nd.nodeType === 3) {
                if (remaining <= nd.nodeValue.length) {
                    try {
                        const sel = window.getSelection();
                        const rng = document.createRange();
                        rng.setStart(nd, remaining);
                        rng.collapse(true);
                        sel.removeAllRanges();
                        sel.addRange(rng);
                    } catch (_) {}
                    return;
                }
                remaining -= nd.nodeValue.length;
            } else if (nd.nodeType === 1 && nd.tagName === 'BR') {
                remaining -= 1;
            }
        }
    }

    /** 是否含 IME／Chrome 在 contenteditable 留下的 font、有色 span（略過 .rt-tag 內）。 */
    function targetEditorHasDecorativeInlineJunk(el) {
        if (!el || el.nodeType !== 1) return false;
        if (el.querySelector('font')) return true;
        for (const s of el.querySelectorAll('span[style]')) {
            if (s.closest('.rt-tag')) continue;
            const st = (s.getAttribute('style') || '').toLowerCase();
            if (/\bcolor\s*:/.test(st)) return true;
        }
        return false;
    }

    /**
     * 清除有色 span／font 等裝飾節點：語意以 extractTextFromEditor 為準，畫面改為 buildTaggedHtml 重建。
     * @param {{ restoreFocus?: boolean }} opts blur 時傳 restoreFocus:false，避免搶焦點。
     */
    function sanitizeTargetEditorInlineArtifacts(editor, seg, row, opts = {}) {
        const restoreFocus = opts.restoreFocus !== false;
        if (!editor || editor.contentEditable === 'false') return false;
        if (!targetEditorHasDecorativeInlineJunk(editor)) return false;
        const plain = extractTextFromEditor(editor);
        let off = null;
        try {
            const sel = window.getSelection();
            if (sel && sel.rangeCount && editor.contains(sel.anchorNode)) off = getNpCaretOffset(editor);
        } catch (_) {}
        setEditorHtml(editor, buildTaggedHtml(plain, effectiveTags(seg)));
        if (row) updateTagColors(row, plain);
        seg.targetText = plain;
        const maxLen = plain.length;
        const clamped = off != null ? Math.max(0, Math.min(off | 0, maxLen)) : null;
        if (restoreFocus && clamped != null) {
            requestAnimationFrame(() => {
                requestAnimationFrame(() => {
                    if (!document.body.contains(editor) || editor.contentEditable === 'false') return;
                    setNpCaretOffset(editor, clamped);
                    editor.focus();
                    saveCatCaretFromSelection(editor);
                    if (row) refreshTagNextHighlight(row);
                    try { runSearchAndFilter(); } catch (_) {}
                });
            });
        } else {
            if (row) refreshTagNextHighlight(row);
            queueMicrotask(() => {
                try { runSearchAndFilter(); } catch (_) {}
            });
        }
        return true;
    }

    /**
     * 設定 rt-editor 的 innerHTML，並在非列印字元模式開啟時自動重新套用標記。
     * 凡是會覆寫 editor innerHTML 的地方都應使用此函數，以確保 data-np-applied 正確清除。
     */
    function setEditorHtml(el, html) {
        if (!el) return;
        el.innerHTML = html;
        el.removeAttribute('data-np-applied');
        if (document.getElementById('editorGrid')?.classList.contains('show-non-print')) {
            requestAnimationFrame(() => applyNonPrintMarkers(el));
        }
        refreshSegCharCount(el);
    }

    /**
     * 計算譯文欄字元數：text node 全計（含空格），rt-tag / non-print-marker span 跳過。
     */
    function countEditorChars(editorEl) {
        if (!editorEl) return 0;
        let n = 0;
        function walkNode(nd) {
            if (nd.nodeType === 3) { n += nd.nodeValue.length; return; }
            if (nd.nodeType !== 1) return;
            if (nd.classList && nd.classList.contains('rt-tag')) return;
            if (nd.classList && nd.classList.contains('non-print-marker')) {
                if (nd.classList.contains('np-inline-char')) nd.childNodes.forEach(walkNode);
                return;
            }
            if (nd.tagName === 'BR') { n++; return; }
            nd.childNodes.forEach(walkNode);
        }
        editorEl.childNodes.forEach(walkNode);
        return n;
    }

    function refreshSegCharCount(editorEl) {
        if (!editorEl) return;
        const colTarget = editorEl.closest && editorEl.closest('.col-target');
        if (!colTarget) return;
        const el = colTarget.querySelector('.seg-char-count');
        if (el) el.textContent = countEditorChars(editorEl);
    }

