    /**
     * Shift+click 範圍勾選通用 helper。
     * @param {HTMLElement} tbody - 含有核取方塊的 tbody
     * @param {string} cbSelector - 核取方塊的 CSS selector（限在 tbody 內）
     * @param {function} [onAfterChange] - 勾選狀態變更後的回呼（可選）
     * @returns {{ destroy: function }} - 呼叫 destroy() 可移除事件監聽
     */
    function _setupShiftRangeSelect(tbody, cbSelector, onAfterChange) {
        let _lastCheckedCb = null;

        function handler(e) {
            const cb = e.target;
            if (!cb.matches(cbSelector)) return;
            if (e.type === 'click' && e.shiftKey && _lastCheckedCb && _lastCheckedCb !== cb) {
                const all = Array.from(tbody.querySelectorAll(cbSelector));
                const iA = all.indexOf(_lastCheckedCb);
                const iB = all.indexOf(cb);
                if (iA >= 0 && iB >= 0) {
                    const [lo, hi] = iA < iB ? [iA, iB] : [iB, iA];
                    const targetState = cb.checked;
                    for (let i = lo; i <= hi; i++) all[i].checked = targetState;
                    if (onAfterChange) onAfterChange();
                }
            }
            _lastCheckedCb = cb;
            if (e.type === 'change' && onAfterChange) onAfterChange();
        }

        tbody.addEventListener('click', handler);
        tbody.addEventListener('change', handler);
        return {
            destroy() {
                tbody.removeEventListener('click', handler);
                tbody.removeEventListener('change', handler);
            }
        };
    }

    // 為檔案清單套用 Shift+click 範圍勾選
    if (filesListBody) {
        _setupShiftRangeSelect(filesListBody, '.project-file-row-cb', syncProjectFilesSelectAll);
    }

    async function loadFilesList() {
        if(!currentProjectId || !filesListBody) return;
        if (isTeamMode()) {
            await requestProjectAssignments(currentProjectId);
        } else {
            window._fileAssigneesByFileId = {};
        }
        const files = await DBService.getFiles(currentProjectId);
        window._lastFilesListForProject = files;
        filesListBody.innerHTML = '';
        /** 專案檔案清單「預設身分」欄：僅此表格使用兩行（T + 第二行說明）；非 mqxliff 不顯示。 */
        function projectFilesListMqRoleCellHtml(defaultMqRole) {
            const esc = (s) => String(s).replace(/</g, '&lt;').replace(/>/g, '&gt;');
            const norm = defaultMqRole === 'T' ? 'T_ALLOW_R1' : String(defaultMqRole || '').trim();
            const sub = (t) => '<div style="font-size:0.76rem;color:#64748b;">' + esc(t) + '</div>';
            if (norm === 'T_ALLOW_R1') {
                return '<div style="line-height:1.25;text-align:center;"><div>T</div>' + sub('可編 R1') + '</div>';
            }
            if (norm === 'T_DENY_R1') {
                return '<div style="line-height:1.25;text-align:center;"><div>T</div>' + sub('不可編 R1') + '</div>';
            }
            if (norm === 'R1') return '<div style="text-align:center;">R1</div>';
            if (norm === 'R2') return '<div style="text-align:center;">R2</div>';
            if (norm) return '<div style="text-align:center;">' + esc(norm) + '</div>';
            return '—';
        }
        if(files.length === 0) {
            const tr = document.createElement('tr');
            tr.innerHTML = '<td colspan="8" style="padding:0.75rem; color:#64748b;">此專案內尚無檔案。請點擊上方按鈕匯入檔案。</td>';
            filesListBody.appendChild(tr);
            await loadWorkspaceNotesList();
            return;
        }

        files.forEach((f, idx) => {
            const tr = document.createElement('tr');
            const nameEsc = (f.name || '').replace(/</g, '&lt;').replace(/>/g, '&gt;');
            const modStr = f.lastModified ? new Date(f.lastModified).toLocaleString('zh-TW', { hour12: false }) : '—';
            const isMqxliff = (f.name || '').toLowerCase().endsWith('.mqxliff');
            const roleTdHtml = isMqxliff ? projectFilesListMqRoleCellHtml(f.defaultMqRole) : '';

            // 語言對顯示（若原始檔語言對不同則附加提示）
            const fileSrc = f.sourceLang || '';
            const fileTgt = f.targetLang || '';
            let fileLangHtml = '';
            if (fileSrc || fileTgt) {
                fileLangHtml = `<div style="display:flex; align-items:center; gap:0.25rem; margin-bottom:0.2rem;">${langBadgeHtml([fileSrc].filter(Boolean))}</div>
                    <div style="display:flex; align-items:center; gap:0.25rem;"><span style="color:#94a3b8;">→</span>${langBadgeHtml([fileTgt].filter(Boolean))}</div>`;
                const origSrc = f.originalSourceLang || '';
                const origTgt = f.originalTargetLang || '';
                const mismatch = (origSrc && origSrc.toLowerCase() !== fileSrc.toLowerCase()) ||
                                 (origTgt && origTgt.toLowerCase() !== fileTgt.toLowerCase());
                if (mismatch) {
                    fileLangHtml += ` <span style="color:#f59e0b; font-size:0.75rem; cursor:help;" title="原始檔語言對：${origSrc} → ${origTgt}">⚠</span>`;
                }
            } else {
                fileLangHtml = '<span style="color:#94a3b8; font-size:0.8rem;">—</span>';
            }

            tr.setAttribute('data-file-id', f.id);
            const aid = String(f.id);
            const assignees = (window._fileAssigneesByFileId && window._fileAssigneesByFileId[aid]) || [];
            const assignPlain = assignees.length ? assignees.join('、') : '';
            const assignCell = assignees.length
                ? assignees.map((n) => `<div style="line-height:1.4;">${String(n).replace(/</g, '&lt;').replace(/>/g, '&gt;')}</div>`).join('')
                : '—';
            const assignTitle = assignPlain.replace(/"/g, '&quot;');
            const progressCellHtml = `
                <div class="file-progress-cell" data-file-id="${f.id}" style="margin-top:0.35rem; width:100%;">
                    <span style="color:#94a3b8; font-size:0.76rem;">載入中…</span>
                </div>
            `;
            tr.innerHTML = `
                <td style="padding:0.5rem; border:1px solid #e2e8f0; text-align:center;"><input type="checkbox" class="project-file-row-cb" data-id="${f.id}"></td>
                <td style="padding:0.5rem; border:1px solid #e2e8f0; width:60px;">${idx + 1}</td>
                <td style="padding:0.5rem; border:1px solid #e2e8f0;"><a href="#" class="edit-file-btn" data-id="${f.id}" style="color:var(--primary-color); text-decoration:underline; cursor:pointer;">${nameEsc}</a>${progressCellHtml}</td>
                <td style="padding:0.5rem; border:1px solid #e2e8f0; font-size:0.82rem;">${fileLangHtml}</td>
                <td style="padding:0.5rem; border:1px solid #e2e8f0; min-width:5.25rem; width:5.5rem; vertical-align:middle;">${roleTdHtml}</td>
                <td style="padding:0.5rem; border:1px solid #e2e8f0; font-size:0.82rem; color:#334155; width:120px; vertical-align:middle;" title="${assignTitle}">${assignCell}</td>
                <td style="padding:0.5rem; border:1px solid #e2e8f0; font-size:0.82rem;">${getFileCaseLinkHtml(f)}</td>
                <td style="padding:0.5rem; border:1px solid #e2e8f0;">${modStr}</td>
            `;
            filesListBody.appendChild(tr);
        });

        filesListBody.querySelectorAll('.edit-file-btn').forEach(btn => {
            btn.addEventListener('click', (e) => {
                e.preventDefault();
                const idAttr = btn.getAttribute('data-id');
                if (!idAttr) return;
                // local mode: Dexie PK is integer; team mode: string UUID
                const id = isTeamMode() ? idAttr : parseInt(idAttr);
                openEditor(id);
            });
        });
        filesListBody.querySelectorAll('.project-file-case-link').forEach((link) => {
            link.addEventListener('click', async (e) => {
                e.preventDefault();
                const fileRow = link.closest('tr');
                const fileId = fileRow?.getAttribute('data-file-id');
                if (!fileId) return;
                const isBound = link.getAttribute('data-case-bound') === '1';
                const linkedCaseId = String(link.getAttribute('data-case-id') || '').trim();
                if (isBound && linkedCaseId && !e.shiftKey) {
                    window.parent.postMessage({
                        type: 'CAT_OPEN_CASE_PAGE',
                        payload: { caseId: linkedCaseId }
                    }, window.location.origin);
                    return;
                }
                openCasePickerDialog([fileId]);
            });
        });
        syncProjectFilesSelectAll();
        await loadWorkspaceNotesList();
        // 非同步載入各檔案進度（不阻塞 UI）
        _loadFilesProgressAsync(files);
    }

    function _fmtProgressNum(x) {
        const n = Number(x);
        if (!Number.isFinite(n)) return '0';
        return String(Math.round(n * 100) / 100);
    }

    function readWcDiscountsFromInputs() {
        const fallback = { tm9599: 0.10, tm8594: 0.25, tm7584: 0.50, tm5074: 0.75, newWords: 1.00, repetition: 0.00 };
        const base = (window.WordCountEngine && WordCountEngine.DEFAULT_DISCOUNTS)
            ? { ...WordCountEngine.DEFAULT_DISCOUNTS }
            : { ...fallback };
        const el9599 = document.getElementById('wordCountDiscount9599');
        const elRep = document.getElementById('wordCountDiscountRep');
        if (el9599 && el9599.value !== '') {
            const n = parseFloat(el9599.value, 10);
            if (Number.isFinite(n)) base.tm9599 = Math.max(0, Math.min(100, n)) / 100;
        }
        if (elRep && elRep.value !== '') {
            const n = parseFloat(elRep.value, 10);
            if (Number.isFinite(n)) base.repetition = Math.max(0, Math.min(100, n)) / 100;
        }
        return base;
    }

    function applyWcDiscountsFromInputs() {
        _wcDiscounts = readWcDiscountsFromInputs();
        _projectTmNormListCache = null;
        _editorTmNormListCache = null;
    }

    async function getProjectTmNormListCached(projectId) {
        if (!projectId || !window.WordCountEngine) return [];
        if (_projectTmNormListCache && String(_projectTmNormListCache.projectId) === String(projectId)) {
            return _projectTmNormListCache.normList;
        }
        const p = await DBService.getProject(projectId);
        const readTms = (p && p.readTms) ? p.readTms : [];
        const tmNormList = [];
        for (const tid of readTms) {
            const segs = await DBService.getTMSegments(tid);
            segs.forEach((s) => {
                const n = WordCountEngine.normKey(s.sourceText);
                if (n) tmNormList.push(n);
            });
        }
        _projectTmNormListCache = { projectId, normList: tmNormList };
        return tmNormList;
    }

    async function _fillOneFileProgressCell(f, pgId, tmNormList, discounts) {
        const WCE = window.WordCountEngine;
        const cell = filesListBody?.querySelector(`.file-progress-cell[data-file-id="${f.id}"]`);
        if (!cell) return;
        const mode = _wcGetFileMode(f.id);
        const useWeighted = mode === 'weighted' && WCE;
        const barColor = useWeighted ? '#ef4444' : 'var(--success-color)';
        const segs = await DBService.getSegmentsByFile(f.id);
        if (!segs || !segs.length) {
            cell.innerHTML = '<span style="color:#94a3b8; font-size:0.76rem;">0 字</span>';
            return;
        }
        let total;
        let confirmed;
        if (!useWeighted) {
            if (WCE) {
                total = segs.reduce((a, s) => a + WCE.weightedUnits(s.sourceText || ''), 0);
                confirmed = segs.filter((s) => s.status === 'confirmed')
                    .reduce((a, s) => a + WCE.weightedUnits(s.sourceText || ''), 0);
            } else {
                total = segs.reduce((a, s) => a + countWords(s.sourceText || ''), 0);
                confirmed = segs.filter((s) => s.status === 'confirmed')
                    .reduce((a, s) => a + countWords(s.sourceText || ''), 0);
            }
        } else {
            const nSeg = segs.length;
            cell.innerHTML = _wcCellLoadingBar(0, nSeg, false);
            const payload = {
                segments: _wcSerializeSegmentsForWorker(segs),
                tmSourcesNormalized: tmNormList,
                includeLocked: true,
                discounts
            };
            const res = await runWcAnalyzeWithFallback(payload, (done, tot) => {
                if (!_wcStillOnProjectDetail(pgId)) return;
                const c = filesListBody?.querySelector(`.file-progress-cell[data-file-id="${f.id}"]`);
                if (c) c.innerHTML = _wcCellLoadingBar(done, tot, false);
            });
            if (!_wcStillOnProjectDetail(pgId)) return;
            const per = res.perSegment || [];
            total = 0;
            confirmed = 0;
            for (let i = 0; i < segs.length; i++) {
                const ps = per[i];
                if (!ps) continue;
                total += ps.weightedW;
                if (segs[i].status === 'confirmed') confirmed += ps.weightedW;
            }
        }
        const pct = total === 0 ? 0 : Math.round(confirmed / total * 100);
        const cell2 = filesListBody?.querySelector(`.file-progress-cell[data-file-id="${f.id}"]`);
        if (cell2) cell2.innerHTML = _wcCellDoneBar(pct, confirmed, total, barColor, false);
    }

    /**
     * @param {object[]} files
     * @param {{ singleFileId?: string|number }} [opts] — 僅重算單一檔案列（不刷整表「載入中」）
     */
    async function _loadFilesProgressAsync(files, opts) {
        opts = opts || {};
        const singleId = opts.singleFileId != null ? String(opts.singleFileId) : null;
        if (!files || !files.length) return;
        const pgId = currentProjectId;
        let workList = files;
        if (singleId) {
            workList = files.filter((ff) => String(ff.id) === singleId);
            if (!workList.length && window._lastFilesListForProject) {
                const meta = window._lastFilesListForProject.find((x) => String(x.id) === singleId);
                if (meta) workList = [meta];
            }
            if (!workList.length) return;
        }
        const anyWeighted = workList.some((ff) => _wcGetFileMode(ff.id) === 'weighted');
        let tmNormList = [];
        if (anyWeighted && pgId) {
            try { tmNormList = await getProjectTmNormListCached(pgId); } catch (_) { /* ignore */ }
        }
        const discounts = readWcDiscountsFromInputs();
        const WCE = window.WordCountEngine;
        const rawList = workList.filter((ff) => !(_wcGetFileMode(ff.id) === 'weighted' && WCE));
        const weightedList = workList.filter((ff) => _wcGetFileMode(ff.id) === 'weighted' && WCE);

        await Promise.all(rawList.map((f) => {
            if (!_wcStillOnProjectDetail(pgId)) return Promise.resolve();
            return _fillOneFileProgressCell(f, pgId, tmNormList, discounts).catch(() => {});
        }));

        for (const f of weightedList) {
            if (!_wcStillOnProjectDetail(pgId)) break;
            try {
                await _fillOneFileProgressCell(f, pgId, tmNormList, discounts);
            } catch (_) { /* team mode 或空檔案時靜默失敗 */ }
        }
        _wcRefreshFileToolbarTitle();
    }

    async function _fillOneViewProgressCell(v, pgId, tmNormList, discounts) {
        const WCE = window.WordCountEngine;
        const segIds = Array.isArray(v.segmentIds) ? v.segmentIds : [];
        const cell = document.querySelector(`.view-progress-cell[data-view-id="${v.id}"]`);
        if (!cell) return;
        if (!segIds.length) {
            cell.innerHTML = '<span style="color:#94a3b8;">0 字</span>';
            return;
        }
        const mode = _wcGetViewMode(v.id);
        const useWeighted = mode === 'weighted' && WCE;
        const barColor = useWeighted ? '#ef4444' : 'var(--success-color)';
        let segs = await DBService.getSegmentsByIds(segIds);
        const orderMap = new Map(segIds.map((id, i) => [String(id), i]));
        segs = (segs || []).slice().sort((a, b) => (orderMap.get(String(a.id)) ?? 0) - (orderMap.get(String(b.id)) ?? 0));
        let total;
        let confirmed;
        if (!useWeighted) {
            if (WCE) {
                total = segs.reduce((a, s) => a + WCE.weightedUnits(s.sourceText || ''), 0);
                confirmed = segs.filter((s) => s.status === 'confirmed')
                    .reduce((a, s) => a + WCE.weightedUnits(s.sourceText || ''), 0);
            } else {
                total = segs.reduce((a, s) => a + countWords(s.sourceText || ''), 0);
                confirmed = segs.filter((s) => s.status === 'confirmed')
                    .reduce((a, s) => a + countWords(s.sourceText || ''), 0);
            }
        } else {
            const nSeg = segs.length;
            cell.innerHTML = _wcCellLoadingBar(0, nSeg, true);
            const payload = {
                segments: _wcSerializeSegmentsForWorker(segs),
                tmSourcesNormalized: tmNormList,
                includeLocked: true,
                discounts
            };
            const res = await runWcAnalyzeWithFallback(payload, (done, tot) => {
                if (!_wcStillOnProjectDetail(pgId)) return;
                const c = document.querySelector(`.view-progress-cell[data-view-id="${v.id}"]`);
                if (c) c.innerHTML = _wcCellLoadingBar(done, tot, true);
            });
            if (!_wcStillOnProjectDetail(pgId)) return;
            const per = res.perSegment || [];
            total = 0;
            confirmed = 0;
            for (let i = 0; i < segs.length; i++) {
                const ps = per[i];
                if (!ps) continue;
                total += ps.weightedW;
                if (segs[i].status === 'confirmed') confirmed += ps.weightedW;
            }
        }
        const pct = total === 0 ? 0 : Math.round(confirmed / total * 100);
        const cell2 = document.querySelector(`.view-progress-cell[data-view-id="${v.id}"]`);
        if (cell2) cell2.innerHTML = _wcCellDoneBar(pct, confirmed, total, barColor, true);
    }

    /** @param {{ singleViewId?: string|number }} [opts] */
    async function _loadViewsProgressAsync(views, opts) {
        opts = opts || {};
        const singleVid = opts.singleViewId != null ? String(opts.singleViewId) : null;
        if (!Array.isArray(views) || !views.length) return;
        const pgId = currentProjectId;
        let workList = views;
        if (singleVid) {
            workList = views.filter((vv) => String(vv.id) === singleVid);
            if (!workList.length && _currentViewsList && _currentViewsList.length) {
                const meta = _currentViewsList.find((x) => String(x.id) === singleVid);
                if (meta) workList = [meta];
            }
            if (!workList.length) return;
        }
        const anyWeighted = workList.some((vv) => _wcGetViewMode(vv.id) === 'weighted');
        let tmNormList = [];
        if (anyWeighted && pgId) {
            try { tmNormList = await getProjectTmNormListCached(pgId); } catch (_) { /* ignore */ }
        }
        const discounts = readWcDiscountsFromInputs();
        const WCE = window.WordCountEngine;
        const rawList = workList.filter((vv) => !(_wcGetViewMode(vv.id) === 'weighted' && WCE));
        const weightedList = workList.filter((vv) => _wcGetViewMode(vv.id) === 'weighted' && WCE);

        await Promise.all(rawList.map((v) => {
            if (!_wcStillOnProjectDetail(pgId)) return Promise.resolve();
            return _fillOneViewProgressCell(v, pgId, tmNormList, discounts).catch(() => {});
        }));

        for (const v of weightedList) {
            if (!_wcStillOnProjectDetail(pgId)) break;
            try {
                await _fillOneViewProgressCell(v, pgId, tmNormList, discounts);
            } catch (_) { /* 靜默失敗 */ }
        }
        _wcRefreshViewToolbarTitle();
    }

    function getSelectedProjectFileIds() {
        if (!filesListBody) return [];
        return Array.from(filesListBody.querySelectorAll('.project-file-row-cb:checked'))
            .map(cb => cb.getAttribute('data-id'))
            .filter(Boolean);
    }

    function closeWordCountModal() {
        if (wordCountModal) wordCountModal.classList.add('hidden');
    }

    function closeSplitAssignModal() {
        if (splitAssignModal) splitAssignModal.classList.add('hidden');
    }

    async function refreshWordCountReportHistory() {
        if (!wordCountReportHistory || !currentProjectId || !DBService.listWordCountReports) return;
        const list = await DBService.listWordCountReports(currentProjectId);
        if (!list.length) {
            wordCountReportHistory.innerHTML = '<li style="color:#64748b;">尚無儲存的報告</li>';
            return;
        }
        wordCountReportHistory.innerHTML = list.map((r) => {
            const at = r.createdAt ? new Date(r.createdAt).toLocaleString('zh-TW', { hour12: false }) : '';
            const lab = (r.label || '').replace(/</g, '&lt;');
            return `<li style="margin-bottom:0.25rem;"><span style="color:#64748b;">${at}</span> — ${lab}</li>`;
        }).join('');
    }

    async function openWordCountModalWithSelection() {
        const ids = getSelectedProjectFileIds();
        if (!ids.length) {
            alert('請先勾選要納入分析的檔案。');
            return;
        }
        if (!currentProjectId || !wordCountModal || !wordCountTmCheckboxes) return;
        wordCountSelectedFileIds = ids.slice();
        const p = await DBService.getProject(currentProjectId);
        const readTms = (p && p.readTms) ? p.readTms : [];
        const allTms = await DBService.getTMs();
        wordCountTmCheckboxes.innerHTML = readTms.length ? readTms.map((tid) => {
            const tm = allTms.find((t) => String(t.id) === String(tid));
            const name = tm ? (tm.name || `TM #${tid}`) : `TM #${tid}`;
            const safe = String(name).replace(/</g, '&lt;');
            return `<label style="display:flex; align-items:center; gap:0.35rem; font-size:0.86rem; cursor:pointer;">
                <input type="checkbox" class="word-count-tm-cb" value="${tid}" checked> ${safe}
            </label>`;
        }).join('') : '<span style="color:#64748b; font-size:0.86rem;">專案尚未掛載讀取 TM（仍可依句段與檔內重複分析）</span>';
        if (wordCountResultBody) wordCountResultBody.innerHTML = '';
        lastWordCountResult = null;
        await refreshWordCountReportHistory();
        wordCountModal.classList.remove('hidden');
    }

    async function runWordCountAnalysis() {
        const segOverride = window._wordCountSegmentOverride;
        if (!window.WordCountEngine || (!wordCountSelectedFileIds.length && !segOverride)) {
            alert('無可分析的檔案。');
            return;
        }
        const includeLocked = !!(wordCountIncludeLocked && wordCountIncludeLocked.checked);
        let tmNormList = [];
        if (wordCountTmCheckboxes) {
            const checked = wordCountTmCheckboxes.querySelectorAll('.word-count-tm-cb:checked');
            for (const cb of checked) {
                const tmId = cb.value;
                if (!tmId) continue;
                const segs = await DBService.getTMSegments(tmId);
                segs.forEach((s) => {
                    const n = WordCountEngine.normKey(s.sourceText);
                    if (n) tmNormList.push(n);
                });
            }
        }
        let allSegments = [];
        if (segOverride) {
            // 句段集分析模式：以 segment IDs 直接載入
            window._wordCountSegmentOverride = null;
            allSegments = await DBService.getSegmentsByIds(segOverride);
        } else {
            for (const fid of wordCountSelectedFileIds) {
                const segs = await DBService.getSegmentsByFile(fid);
                allSegments = allSegments.concat(segs);
            }
        }
        applyWcDiscountsFromInputs();
        lastWordCountResult = WordCountEngine.analyze({
            segments: allSegments,
            tmSourcesNormalized: tmNormList,
            includeLocked,
            discounts: _wcDiscounts
        });
        if (wordCountResultBody) {
            const t = lastWordCountResult.totals || {};
            const head = `<tr style="background:#f8fafc;"><td style="padding:0.45rem; border:1px solid #e2e8f0; font-weight:600;">分析範圍總計（略過鎖定後）</td>
                <td style="padding:0.45rem; border:1px solid #e2e8f0; text-align:right;">${t.segmentsAnalyzed != null ? t.segmentsAnalyzed : '—'}</td>
                <td style="padding:0.45rem; border:1px solid #e2e8f0; text-align:right;">${t.rawExcludingSkipped != null ? t.rawExcludingSkipped : '—'}</td>
                <td style="padding:0.45rem; border:1px solid #e2e8f0; text-align:right;">${t.weightedExcludingSkipped != null ? t.weightedExcludingSkipped : '—'}</td></tr>`;
            const body = (lastWordCountResult.rows || []).map((r) =>
                `<tr><td style="padding:0.45rem; border:1px solid #e2e8f0;">${r.label}</td>
                <td style="padding:0.45rem; border:1px solid #e2e8f0; text-align:right;">${r.segments}</td>
                <td style="padding:0.45rem; border:1px solid #e2e8f0; text-align:right;">${r.raw}</td>
                <td style="padding:0.45rem; border:1px solid #e2e8f0; text-align:right;">${r.weighted}</td></tr>`
            ).join('');
            wordCountResultBody.innerHTML = head + body;
        }
    }

    async function saveWordCountReport() {
        if (!lastWordCountResult || !currentProjectId) {
            alert('請先執行分析。');
            return;
        }
        const label = new Date().toLocaleString('zh-TW', { hour12: false });
        await DBService.addWordCountReport({
            projectId: currentProjectId,
            label,
            payload: {
                fileIds: wordCountSelectedFileIds.slice(),
                result: lastWordCountResult,
                includeLocked: !!(wordCountIncludeLocked && wordCountIncludeLocked.checked)
            }
        });
        await refreshWordCountReportHistory();
        alert('已儲存至本機報告紀錄。');
    }

    const SPLIT_HINT_QUOTA_EPS = 1e-4;

    function fmtSplitHintNum(x) {
        if (typeof x !== 'number' || !Number.isFinite(x)) return '—';
        return String(Math.round(x * 100) / 100);
    }

    function computeSplitHintQuotas(totalWeighted, n, filledValues) {
        const eps = SPLIT_HINT_QUOTA_EPS;
        const T = totalWeighted;
        const filled = [];
        for (let i = 0; i < n; i++) {
            filled.push(i < filledValues.length ? filledValues[i] : null);
        }
        let S = 0;
        const blanks = [];
        for (let i = 0; i < n; i++) {
            const v = filled[i];
            if (v === null || v === undefined || Number.isNaN(v)) {
                blanks.push(i);
            } else {
                S += v;
            }
        }
        const B = blanks.length;
        const quotas = new Array(n);

        if (B === 0) {
            if (Math.abs(S - T) > eps) {
                return { error: `已填配額加總 ${fmtSplitHintNum(S)} 須等於總加權 ${fmtSplitHintNum(T)}（容許誤差 ${eps}）。` };
            }
            for (let i = 0; i < n; i++) quotas[i] = filled[i];
            for (let i = 0; i < n - 1; i++) {
                if (quotas[i] <= eps) {
                    return { error: `第 ${i + 1} 份的目標加權必須大於 ${eps}。` };
                }
            }
            return { quotas };
        }

        const R = T - S;
        if (R < -eps) {
            return { error: `已填配額加總 ${fmtSplitHintNum(S)} 超過總加權 ${fmtSplitHintNum(T)}。` };
        }
        if (R <= eps && B > 0) {
            return { error: '已填配額加總已達（或超過）總加權，無法再為留白份量分配剩餘配額。' };
        }

        for (let i = 0; i < n; i++) {
            if (blanks.indexOf(i) === -1) quotas[i] = filled[i];
        }
        const Bcnt = B;
        const per = R / Bcnt;
        let acc = 0;
        for (let j = 0; j < Bcnt - 1; j++) {
            const idx = blanks[j];
            quotas[idx] = per;
            acc += per;
        }
        quotas[blanks[Bcnt - 1]] = R - acc;

        for (let i = 0; i < n - 1; i++) {
            if (quotas[i] <= eps) {
                return { error: `第 ${i + 1} 份的目標加權必須大於 ${eps}（含留白均分結果）。` };
            }
        }
        return { quotas };
    }

    function partitionFlatByQuotas(flat, quotas, n) {
        const slices = Array.from({ length: n }, () => []);
        if (!flat || !flat.length) return slices;
        const eps = SPLIT_HINT_QUOTA_EPS;
        let fi = 0;
        for (let p = 0; p < n; p++) {
            const target = quotas[p];
            let sum = 0;
            while (fi < flat.length) {
                const w = flat[fi].weight || 0;
                const lastPart = (p === n - 1);
                if (!lastPart && sum > 0 && sum + w > target + eps) break;
                slices[p].push(flat[fi++]);
                sum += w;
            }
        }
        while (fi < flat.length) {
            slices[n - 1].push(flat[fi++]);
        }
        return slices;
    }

    function rangeTextFromSlice(slice) {
        if (!slice || !slice.length) return '—';
        const byFile = {};
        slice.forEach((item) => {
            if (!byFile[item.fileName]) byFile[item.fileName] = { min: item.rowInFile, max: item.rowInFile };
            else {
                byFile[item.fileName].min = Math.min(byFile[item.fileName].min, item.rowInFile);
                byFile[item.fileName].max = Math.max(byFile[item.fileName].max, item.rowInFile);
            }
        });
        return Object.keys(byFile).map((fn) => {
            const o = byFile[fn];
            return o.min === o.max ? `${fn}：第 ${o.min} 句` : `${fn}：第 ${o.min}–${o.max} 句`;
        }).join('<br>');
    }

    function readSplitHintFilledValues(n) {
        const out = [];
        for (let i = 0; i < n; i++) {
            const el = document.getElementById(`splitHintQuotaInput${i}`);
            if (!el) {
                out.push(null);
                continue;
            }
            const raw = String(el.value != null ? el.value : '').trim();
            if (raw === '') {
                out.push(null);
                continue;
            }
            const num = parseFloat(raw);
            out.push(Number.isFinite(num) ? num : null);
        }
        return out;
    }

    function renderSplitHintQuotaRows(n) {
        if (!splitHintQuotaContainer) return;
        let html = '<div style="display:flex; flex-direction:column; gap:0.35rem;">';
        for (let i = 0; i < n; i++) {
            html += `<div style="display:flex; align-items:center; gap:0.5rem; flex-wrap:wrap;">
                <label style="min-width:4rem;">第 ${i + 1} 份</label>
                <input type="number" id="splitHintQuotaInput${i}" step="any" min="0" placeholder="留白均分" style="flex:1; min-width:8rem; padding:0.3rem 0.45rem; border:1px solid #e2e8f0; border-radius:6px;" />
            </div>`;
        }
        html += '</div>';
        splitHintQuotaContainer.innerHTML = html;
    }

    async function runSplitHintWeightedPreview(fileIds, parts) {
        const wrap = splitAssignTableWrap;
        if (!wrap || !fileIds || !fileIds.length) return;
        const n = Math.max(2, Math.min(99, parseInt(parts, 10) || 2));
        wrap.innerHTML = '<div style="padding:0.75rem;color:#64748b;">計算中…</div>';

        const includeLocked = !!(splitHintIncludeLocked && splitHintIncludeLocked.checked);

        applyWcDiscountsFromInputs();
        const TM_DISCOUNT = _wcDiscounts;

        // Build TM norm list from checked TMs
        let tmNormList = [];
        const useTm = !!(splitHintTmCheckboxes && splitHintTmCheckboxes.querySelector('.split-hint-tm-cb:checked'));
        if (useTm && window.WordCountEngine) {
            const checked = splitHintTmCheckboxes.querySelectorAll('.split-hint-tm-cb:checked');
            for (const cb of checked) {
                const tmId = cb.value;
                if (!tmId) continue;
                const segs = await DBService.getTMSegments(tmId);
                segs.forEach((s) => {
                    const nk = WordCountEngine.normKey(s.sourceText);
                    if (nk) tmNormList.push(nk);
                });
            }
        }
        const tmExact = new Set(tmNormList.filter(Boolean));

        const fileRows = [];
        for (const fid of fileIds) {
            const segs = await DBService.getSegmentsByFile(fid);
            const file = await DBService.getFile(fid);
            fileRows.push({
                name: file && file.name ? file.name : String(fid),
                segs: segs || []
            });
        }
        const flat = [];
        let totalW = 0;
        const seenSrc = new Set();
        fileRows.forEach((fr) => {
            fr.segs.forEach((s, i) => {
                const isLocked = !!(s.isLocked || s.isLockedUser || s.isLockedSystem);
                if (!includeLocked && isLocked) return;
                const WCE = window.WordCountEngine;
                const rawW = (WCE && WCE.weightedUnits) ? WCE.weightedUnits(s.sourceText || '') : 0;
                let w = rawW;
                if (useTm && WCE && tmNormList.length) {
                    const srcN = WCE.normKey(s.sourceText || '');
                    let bucketKey = 'newWords';
                    if (seenSrc.has(srcN)) {
                        bucketKey = 'repetition';
                    } else {
                        seenSrc.add(srcN);
                        if (tmExact.has(srcN)) {
                            bucketKey = 'tm9599';
                        } else {
                            const sim = WCE._bestTmSimilarity(srcN, tmNormList);
                            if (sim >= 0.95) bucketKey = 'tm9599';
                            else if (sim >= 0.85) bucketKey = 'tm8594';
                            else if (sim >= 0.75) bucketKey = 'tm7584';
                            else if (sim >= 0.50) bucketKey = 'tm5074';
                            else bucketKey = 'newWords';
                        }
                    }
                    w = rawW * (TM_DISCOUNT[bucketKey] ?? 1.0);
                } else {
                    const srcN = WCE ? WCE.normKey(s.sourceText || '') : (s.sourceText || '');
                    if (!seenSrc.has(srcN)) seenSrc.add(srcN);
                }
                totalW += w;
                flat.push({ fileName: fr.name, rowInFile: i + 1, weight: w });
            });
        });
        const totalSegs = flat.length;

        const filledValues = readSplitHintFilledValues(n);
        const qres = computeSplitHintQuotas(totalW, n, filledValues);
        if (qres.error) {
            const errText = String(qres.error).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
            wrap.innerHTML = `<div style="padding:0.75rem; color:#dc2626; font-size:0.88rem;">${errText}</div>`;
            return;
        }

        const partSlices = partitionFlatByQuotas(flat, qres.quotas, n);

        const tmNote = (useTm && tmNormList.length) ? '（已套用 TM 折扣）' : '';
        const lockedNote = includeLocked ? '' : '、已略過鎖定句段';
        let html = `<p style="margin:0 0 0.5rem 0; font-size:0.85rem; color:#64748b;">勾選檔案合計 <strong>${totalSegs}</strong> 句${lockedNote}、加權約 <strong>${fmtSplitHintNum(totalW)}</strong>${tmNote}；分為 <strong>${n}</strong> 份（僅供參考）：</p>`;
        html += '<table class="resource-table" style="width:100%; border-collapse:collapse; font-size:0.85rem;"><thead><tr style="background:#f1f5f9;">';
        html += '<th style="text-align:left; padding:0.45rem; border:1px solid #e2e8f0;">份次</th>';
        html += '<th style="text-align:right; padding:0.45rem; border:1px solid #e2e8f0;">目標加權</th>';
        html += '<th style="text-align:right; padding:0.45rem; border:1px solid #e2e8f0;">實際加權</th>';
        html += '<th style="text-align:right; padding:0.45rem; border:1px solid #e2e8f0;">句段數</th>';
        html += '<th style="text-align:left; padding:0.45rem; border:1px solid #e2e8f0;">範圍</th></tr></thead><tbody>';

        for (let p = 0; p < n; p++) {
            const slice = partSlices[p] || [];
            const actualW = slice.reduce((acc, it) => acc + (it.weight || 0), 0);
            const cnt = slice.length;
            const rangeText = rangeTextFromSlice(slice);
            const target = qres.quotas[p];
            html += `<tr><td style="padding:0.45rem; border:1px solid #e2e8f0;">第 ${p + 1} 份</td>`;
            html += `<td style="padding:0.45rem; border:1px solid #e2e8f0; text-align:right;">${fmtSplitHintNum(target)}</td>`;
            html += `<td style="padding:0.45rem; border:1px solid #e2e8f0; text-align:right;">${fmtSplitHintNum(actualW)}</td>`;
            html += `<td style="padding:0.45rem; border:1px solid #e2e8f0; text-align:right;">${cnt}</td>`;
            html += `<td style="padding:0.45rem; border:1px solid #e2e8f0; font-size:0.82rem;">${rangeText}</td></tr>`;
        }
        html += '</tbody></table>';
        wrap.innerHTML = html;
    }

    /** 拆分：以 segment IDs 直接計算（句段集模式） */
    async function runSplitHintWeightedPreviewBySegIds(segIds, parts) {
        const wrap = splitAssignTableWrap;
        if (!wrap || !segIds || !segIds.length) return;
        const n = Math.max(2, Math.min(99, parseInt(parts, 10) || 2));
        wrap.innerHTML = '<div style="padding:0.75rem;color:#64748b;">計算中…</div>';
        const includeLocked = !!(splitHintIncludeLocked && splitHintIncludeLocked.checked);
        applyWcDiscountsFromInputs();
        const TM_DISCOUNT = _wcDiscounts;
        let tmNormList = [];
        const useTm = !!(splitHintTmCheckboxes && splitHintTmCheckboxes.querySelector('.split-hint-tm-cb:checked'));
        if (useTm && window.WordCountEngine) {
            const checked = splitHintTmCheckboxes.querySelectorAll('.split-hint-tm-cb:checked');
            for (const cb of checked) {
                const tmId = cb.value;
                if (!tmId) continue;
                const segs = await DBService.getTMSegments(tmId);
                segs.forEach((s) => { const nk = WordCountEngine.normKey(s.sourceText); if (nk) tmNormList.push(nk); });
            }
        }
        const tmExact = new Set(tmNormList.filter(Boolean));
        let allSegs = await DBService.getSegmentsByIds(segIds);
        const orderMap = new Map(segIds.map((id, i) => [String(id), i]));
        allSegs = (allSegs || []).slice().sort((a, b) => (orderMap.get(String(a.id)) ?? 0) - (orderMap.get(String(b.id)) ?? 0));
        const flat = [];
        let totalW = 0;
        const seenSrc = new Set();
        allSegs.forEach((s, i) => {
            const isLocked = !!(s.isLocked || s.isLockedUser || s.isLockedSystem);
            if (!includeLocked && isLocked) return;
            const WCE = window.WordCountEngine;
            const rawW = (WCE && WCE.weightedUnits) ? WCE.weightedUnits(s.sourceText || '') : 0;
            let w = rawW;
            if (useTm && WCE && tmNormList.length) {
                const srcN = WCE.normKey(s.sourceText || '');
                let bucketKey = 'newWords';
                if (seenSrc.has(srcN)) {
                    bucketKey = 'repetition';
                } else {
                    seenSrc.add(srcN);
                    if (tmExact.has(srcN)) {
                        bucketKey = 'tm9599';
                    } else {
                        const sim = WCE._bestTmSimilarity(srcN, tmNormList);
                        if (sim >= 0.95) bucketKey = 'tm9599';
                        else if (sim >= 0.85) bucketKey = 'tm8594';
                        else if (sim >= 0.75) bucketKey = 'tm7584';
                        else if (sim >= 0.50) bucketKey = 'tm5074';
                        else bucketKey = 'newWords';
                    }
                }
                w = rawW * (TM_DISCOUNT[bucketKey] ?? 1.0);
            } else {
                const srcN = WCE ? WCE.normKey(s.sourceText || '') : (s.sourceText || '');
                if (!seenSrc.has(srcN)) seenSrc.add(srcN);
            }
            totalW += w;
            flat.push({ fileName: '句段集', rowInFile: i + 1, weight: w });
        });
        const totalSegs = flat.length;
        const filledValues = readSplitHintFilledValues(n);
        const qres = computeSplitHintQuotas(totalW, n, filledValues);
        if (qres.error) {
            wrap.innerHTML = `<div style="padding:0.75rem; color:#dc2626; font-size:0.88rem;">${String(qres.error).replace(/</g, '&lt;')}</div>`;
            return;
        }
        const partSlices = partitionFlatByQuotas(flat, qres.quotas, n);
        const tmNote = (useTm && tmNormList.length) ? '（已套用 TM 折扣）' : '';
        const lockedNote = includeLocked ? '' : '、已略過鎖定句段';
        let html = `<p style="margin:0 0 0.5rem 0; font-size:0.85rem; color:#64748b;">所選句段集合計 <strong>${totalSegs}</strong> 句${lockedNote}、加權約 <strong>${fmtSplitHintNum(totalW)}</strong>${tmNote}；分為 <strong>${n}</strong> 份（僅供參考）：</p>`;
        html += '<table class="resource-table" style="width:100%; border-collapse:collapse; font-size:0.85rem;"><thead><tr style="background:#f1f5f9;">';
        html += '<th style="text-align:left; padding:0.45rem; border:1px solid #e2e8f0;">份次</th>';
        html += '<th style="text-align:right; padding:0.45rem; border:1px solid #e2e8f0;">目標加權</th>';
        html += '<th style="text-align:right; padding:0.45rem; border:1px solid #e2e8f0;">實際加權</th>';
        html += '<th style="text-align:right; padding:0.45rem; border:1px solid #e2e8f0;">句段數</th>';
        html += '<th style="text-align:left; padding:0.45rem; border:1px solid #e2e8f0;">範圍</th></tr></thead><tbody>';
        for (let p = 0; p < n; p++) {
            const slice = partSlices[p] || [];
            const actualW = slice.reduce((acc, it) => acc + (it.weight || 0), 0);
            const cnt = slice.length;
            const rangeText = rangeTextFromSlice(slice);
            const target = qres.quotas[p];
            html += `<tr><td style="padding:0.45rem; border:1px solid #e2e8f0;">第 ${p + 1} 份</td>`;
            html += `<td style="padding:0.45rem; border:1px solid #e2e8f0; text-align:right;">${fmtSplitHintNum(target)}</td>`;
            html += `<td style="padding:0.45rem; border:1px solid #e2e8f0; text-align:right;">${fmtSplitHintNum(actualW)}</td>`;
            html += `<td style="padding:0.45rem; border:1px solid #e2e8f0; text-align:right;">${cnt}</td>`;
            html += `<td style="padding:0.45rem; border:1px solid #e2e8f0; font-size:0.82rem;">${rangeText}</td></tr>`;
        }
        html += '</tbody></table>';
        wrap.innerHTML = html;
    }

    async function openSplitHintModal() {
        const ids = getSelectedProjectFileIds();
        if (!ids.length) {
            alert('請先勾選檔案。');
            return;
        }
        const raw = splitHintPartsInput ? parseInt(splitHintPartsInput.value, 10) : 2;
        const n = Math.max(2, Math.min(99, Number.isFinite(raw) ? raw : 2));
        if (splitHintPartsInput) splitHintPartsInput.value = String(n);
        renderSplitHintQuotaRows(n);
        if (splitAssignTableWrap) {
            splitAssignTableWrap.innerHTML = '<div style="padding:0.75rem; color:#64748b; font-size:0.88rem;">設定份數與選填配額後，按「開始計算」。</div>';
        }
        // Populate TM checkboxes
        if (splitHintTmCheckboxes && currentProjectId) {
            const p = await DBService.getProject(currentProjectId);
            const readTms = (p && p.readTms) ? p.readTms : [];
            const allTms = await DBService.getTMs();
            splitHintTmCheckboxes.innerHTML = readTms.length ? readTms.map((tid) => {
                const tm = allTms.find((t) => String(t.id) === String(tid));
                const name = tm ? (tm.name || `TM #${tid}`) : `TM #${tid}`;
                const safe = String(name).replace(/</g, '&lt;');
                return `<label style="display:flex; align-items:center; gap:0.35rem; font-size:0.86rem; cursor:pointer;">
                    <input type="checkbox" class="split-hint-tm-cb" value="${tid}" checked> ${safe}
                </label>`;
            }).join('') : '<span style="color:#64748b; font-size:0.86rem;">專案尚未掛載讀取 TM（加權以原文字數計算）</span>';
        }
        if (splitAssignModal) splitAssignModal.classList.remove('hidden');
    }

