    async function applyTbListFilter() {
        const q = (tbSearchInput && tbSearchInput.value.trim()) || '';
        const filtered = q
            ? lastTbListItems.filter(t => (t.name || '').toLowerCase().includes(q.toLowerCase()))
            : lastTbListItems;
        await baseResourceList('getTBs', 'deleteTB', tbList, filtered);
    }

