    if (viewsListBody && !viewsListBody.dataset.wcViewProgressClick) {
        viewsListBody.dataset.wcViewProgressClick = '1';
        viewsListBody.addEventListener('click', async (e) => {
            const cell = e.target.closest('.view-progress-cell');
            if (!cell || !viewsListBody.contains(cell)) return;
            e.preventDefault();
            e.stopPropagation();
            const vid = cell.getAttribute('data-view-id');
            if (!vid) return;
            const cur = _wcGetViewMode(vid);
            _viewProgressModeById[vid] = cur === 'raw' ? 'weighted' : 'raw';
            _wcRefreshViewToolbarTitle();
            if (_currentViewsList && _currentViewsList.length) {
                await _loadViewsProgressAsync(_currentViewsList, { singleViewId: vid });
            }
        });
    }
    const editorProgressTrack = document.querySelector('.editor-status-bar-progress-track');
    if (editorProgressTrack && !editorProgressTrack.dataset.wcEditorProgressClick) {
        editorProgressTrack.dataset.wcEditorProgressClick = '1';
        editorProgressTrack.addEventListener('click', async () => {
            if (currentFileId == null) return;
            const cur = _wcGetEditorModeForFile(currentFileId);
            _editorProgressModeByFileId[String(currentFileId)] = cur === 'raw' ? 'weighted' : 'raw';
            _editorTmNormListCache = null;
            await updateProgress();
            _wcRefreshEditorToolbarTitle();
        });
    }

    /** 進度條上無延遲自訂提示（原生 title 有延遲）；role="tooltip" + aria-describedby */
    (function initWcProgressModeTooltip() {
        const TIP_ID = 'wcProgressModeTooltip';
        let activeTrigger = null;
        function ensureTipEl() {
            let tip = document.getElementById(TIP_ID);
            if (!tip) {
                tip = document.createElement('div');
                tip.id = TIP_ID;
                tip.className = 'wc-progress-mode-tooltip hidden';
                tip.setAttribute('role', 'tooltip');
                tip.setAttribute('aria-hidden', 'true');
                document.body.appendChild(tip);
            }
            return tip;
        }
        function tipTextFor(el) {
            if (el.classList.contains('file-progress-cell')) {
                const id = el.getAttribute('data-file-id');
                const m = _wcGetFileMode(id);
                return `切換本列字數顯示方式；目前顯示：${m === 'weighted' ? '加權字數' : '原始字數'}`;
            }
            if (el.classList.contains('view-progress-cell')) {
                const id = el.getAttribute('data-view-id');
                const m = _wcGetViewMode(id);
                return `切換本列字數顯示方式；目前顯示：${m === 'weighted' ? '加權字數' : '原始字數'}`;
            }
            if (el.classList.contains('editor-status-bar-progress-track')) {
                const m = currentFileId != null ? _wcGetEditorModeForFile(currentFileId) : 'raw';
                return `切換本列字數顯示方式；目前顯示：${m === 'weighted' ? '加權字數' : '原始字數'}`;
            }
            return '';
        }
        function hideTip() {
            const tip = document.getElementById(TIP_ID);
            if (activeTrigger) {
                activeTrigger.removeAttribute('aria-describedby');
                activeTrigger = null;
            }
            if (tip) {
                tip.classList.add('hidden');
                tip.setAttribute('aria-hidden', 'true');
                tip.textContent = '';
            }
        }
        function showTip(el) {
            const text = tipTextFor(el);
            if (!text) return;
            hideTip();
            activeTrigger = el;
            const tip = ensureTipEl();
            tip.textContent = text;
            el.setAttribute('aria-describedby', TIP_ID);
            tip.classList.remove('hidden');
            tip.setAttribute('aria-hidden', 'false');
            requestAnimationFrame(() => {
                if (!activeTrigger || activeTrigger !== el) return;
                const r = el.getBoundingClientRect();
                const tr = tip.getBoundingClientRect();
                let left = r.left + (r.width - tr.width) / 2;
                let top = r.bottom + 6;
                if (left < 8) left = 8;
                if (left + tr.width > window.innerWidth - 8) left = Math.max(8, window.innerWidth - 8 - tr.width);
                if (top + tr.height > window.innerHeight - 8) top = r.top - tr.height - 6;
                if (top < 8) top = 8;
                tip.style.left = `${Math.round(left)}px`;
                tip.style.top = `${Math.round(top)}px`;
            });
        }
        document.addEventListener('mouseover', (e) => {
            const el = e.target.closest('.file-progress-cell, .view-progress-cell, .editor-status-bar-progress-track');
            if (!el) return;
            if (activeTrigger === el) return;
            showTip(el);
        }, true);
        document.addEventListener('mouseout', (e) => {
            if (!activeTrigger) return;
            const rel = e.relatedTarget;
            if (rel && activeTrigger.contains(rel)) return;
            hideTip();
        }, true);
        window.addEventListener('scroll', () => {
            const tip = document.getElementById(TIP_ID);
            if (tip && !tip.classList.contains('hidden')) hideTip();
        }, true);
        window.addEventListener('resize', () => {
            const tip = document.getElementById(TIP_ID);
            if (tip && !tip.classList.contains('hidden')) hideTip();
        });
    })();

    // ── QA ──────────────────────────────────────────────────────────────────

    let _qaResults = [];
    const _qaIgnoredSet = new Set(); // key: `${gid}:${type}:${detail}`
    let qaSortKey = 'gid';
    let qaSortDir = 'asc';
    let qaLastRunSummaryHtml = '';

    function _qaJumpToSegment(segId) {
        const row = document.querySelector(`.grid-data-row[data-seg-id="${segId}"]`);
        if (!row) { alert('句段目前不在可見列表中（可能被篩選隱藏），請移除篩選後再試。'); return; }
        row.scrollIntoView({ behavior: 'smooth', block: 'center' });
        const ta = row.querySelector('.grid-textarea');
        if (ta) ta.focus();
    }

    function _qaStripTagsPlain(raw) {
        const Xliff = window.CatToolXliffTags;
        if (Xliff && raw) {
            try {
                const r = Xliff.extractTaggedText(raw);
                if (r && typeof r.clean === 'string') return r.clean;
            } catch (_) { /* ignore */ }
        }
        return raw || '';
    }

    function _qaNormFwDigits(s) {
        return String(s || '').replace(/[\uFF10-\uFF19]/g, ch =>
            String.fromCharCode(ch.charCodeAt(0) - 0xFEE0));
    }

    function _qaDigitRunsFromPlain(clean) {
        const n = _qaNormFwDigits(clean);
        return (n.match(/\d+/g) || []).slice();
    }

    /** Tag／術語／數字（不含譯文不一致、不含錯字）— 供 runQaChecks 與確認後增量更新共用 */
    function _qaPushSegmentRuleFindings(results, s, gid, { checkTerms = true, checkTags = true, checkNumbers = true }) {
        if (checkTags) {
            const srcIds = (s.sourceTags || []).map(t => String(t.id ?? t.num ?? t.index ?? ''));
            const tgtIds = (s.targetTags || []).map(t => String(t.id ?? t.num ?? t.index ?? ''));
            if (srcIds.length > 0) {
                const srcSet = new Set(srcIds);
                const tgtSet = new Set(tgtIds);
                const missing = srcIds.filter(id => id && !tgtSet.has(id));
                const extra = tgtIds.filter(id => id && !srcSet.has(id));
                const hasMissing = [...new Set(missing)].length > 0;
                const hasExtra = [...new Set(extra)].length > 0;
                if (hasMissing || hasExtra) {
                    const detail = hasMissing
                        ? '缺少 tag：{' + [...new Set(missing)].join('}, {') + '}'
                        : '多餘 tag：{' + [...new Set(extra)].join('}, {') + '}';
                    results.push({ segId: s.id, gid, type: 'Tag 檢查', info: detail, key: `${gid}:tag` });
                }
            }
        }
        if (checkTerms && window.ActiveTbTerms && window.ActiveTbTerms.length > 0) {
            for (const term of window.ActiveTbTerms) {
                if (!term.source || !term.target) continue;
                if (termMatches(s.sourceText || '', term.source, term.matchFlags) &&
                    !termMatches(s.targetText || '', term.target, term.matchFlags)) {
                    const detail = `「${term.source}」→「${term.target}」`;
                    results.push({ segId: s.id, gid, type: '術語未套用', info: detail, key: `${gid}:tb:${term.source}` });
                }
            }
        }
        if (checkNumbers) {
            const srcRuns = _qaDigitRunsFromPlain(_qaStripTagsPlain(s.sourceText || ''));
            const tgtRuns = _qaDigitRunsFromPlain(_qaStripTagsPlain(s.targetText || ''));
            if (srcRuns.length > 0 || tgtRuns.length > 0) {
                let same = srcRuns.length === tgtRuns.length;
                if (same) {
                    for (let di = 0; di < srcRuns.length; di++) {
                        if (srcRuns[di] !== tgtRuns[di]) { same = false; break; }
                    }
                }
                if (!same) {
                    const fmt = (arr) => (arr.length ? arr.join('、') : '（無）');
                    results.push({
                        segId: s.id, gid, type: '數字不相符',
                        info: `原文數字序列：${fmt(srcRuns)}；譯文：${fmt(tgtRuns)}`,
                        key: `${gid}:digits`
                    });
                }
            }
        }
    }

    function _qaIsTypoLikeResult(r) {
        const t = r && r.type;
        return t === '錯字' || t === '錯字／打字' || t === '錯字/打字';
    }

    /**
     * 句段確認成功且 TM／重複傳播完成後：增量更新 QA 清單（不重跑 AI 錯字）。
     * @param {Iterable<number|string>} segIds 受影響句段 id（含傳播後內容已更新的句段）
     */
    function _qaIncrementalRefreshAfterConfirm(segIds) {
        if (!_qaResults.length) return;
        const idSet = new Set();
        for (const raw of segIds) {
            if (raw == null || raw === '') continue;
            const id = typeof raw === 'string' ? parseId(raw) : raw;
            if (id != null && id !== '') idSet.add(id);
        }
        if (idSet.size === 0) return;

        const checkTerms = document.getElementById('qaCheckTerms')?.checked ?? true;
        const checkTags = document.getElementById('qaCheckTags')?.checked ?? true;
        const checkConsistency = document.getElementById('qaCheckConsistency')?.checked ?? true;
        const checkNumbers = document.getElementById('qaCheckNumbers')?.checked ?? true;
        const includeLocked = document.getElementById('qaIncludeLocked')?.checked ?? false;

        const touchedSources = new Set();
        for (const sid of idSet) {
            const s = currentSegmentsList.find((x) => x.id === sid);
            if (!s) continue;
            const sk = (s.sourceText || '').trim();
            if (sk) touchedSources.add(sk);
        }

        _qaResults = _qaResults.filter((r) => {
            if (_qaIsTypoLikeResult(r)) return true;
            if (r.type === '譯文不一致') {
                const seg = currentSegmentsList.find((x) => x.id === r.segId);
                const sk = (seg?.sourceText || '').trim();
                if (touchedSources.has(sk)) return false;
                return true;
            }
            if (idSet.has(r.segId)) return false;
            return true;
        });

        const newChunks = [];
        for (const sid of idSet) {
            const s = currentSegmentsList.find((x) => x.id === sid);
            if (!s) continue;
            if (!includeLocked && (isDynamicForbidden(s) || s.isLockedUser)) continue;
            if (!s.targetText || !String(s.targetText).trim()) continue;
            const gid = s.globalId || (s.rowIdx + 1);
            _qaPushSegmentRuleFindings(newChunks, s, gid, { checkTerms, checkTags, checkNumbers });
        }
        if (newChunks.length) _qaResults.push(...newChunks);

        if (checkConsistency && touchedSources.size) {
            /** trim 原文 → 有非空譯文之句段（與舊版逐 source filter 全檔語意相同，單次掃描） */
            const segsByTrimmedSource = new Map();
            for (const s of currentSegmentsList) {
                const sk = (s.sourceText || '').trim();
                if (!sk || !String(s.targetText || '').trim()) continue;
                let arr = segsByTrimmedSource.get(sk);
                if (!arr) {
                    arr = [];
                    segsByTrimmedSource.set(sk, arr);
                }
                arr.push(s);
            }
            for (const src of touchedSources) {
                const groupSegs = segsByTrimmedSource.get(src) || [];
                const variants = new Set(groupSegs.map((s) => (s.targetText || '').trim()));
                if (variants.size > 1) {
                    for (const s of groupSegs) {
                        const gid = s.globalId || (s.rowIdx + 1);
                        _qaResults.push({
                            segId: s.id,
                            gid,
                            type: '譯文不一致',
                            info: `此原文有 ${variants.size} 種不同譯文`,
                            key: `${gid}:consistency`
                        });
                    }
                }
            }
        }

        renderQaResults();
    }

    function runQaChecks(segs, options) {
        const { fromIdx, toIdx, includeLocked, allowedSegIds,
                checkTerms = true, checkTags = true, checkConsistency = true, checkNumbers = true } = options || {};
        const results = [];

        // 依原始排序（globalId or rowIdx+1）決定範圍索引
        const originalOrdered = [...segs].sort((a, b) => (a.rowIdx ?? 0) - (b.rowIdx ?? 0));

        // 先建立範圍內有譯文的句段清單（供一致性檢查用）
        const filteredSegs = [];
        for (let oi = 0; oi < originalOrdered.length; oi++) {
            const s = originalOrdered[oi];
            const rangeIdx = oi + 1;
            if (fromIdx != null && rangeIdx < fromIdx) continue;
            if (toIdx != null && rangeIdx > toIdx) continue;
            if (allowedSegIds && !allowedSegIds.has(s.id)) continue;
            if (!includeLocked && (isDynamicForbidden(s) || s.isLockedUser)) continue;
            if (!s.targetText || !s.targetText.trim()) continue;
            filteredSegs.push({ s, gid: s.globalId || (s.rowIdx + 1) });
        }

        // 譯文一致性：建立 sourceText → Set<targetText>
        let consistencyMap = null;
        if (checkConsistency) {
            consistencyMap = new Map();
            for (const { s } of filteredSegs) {
                const src = (s.sourceText || '').trim();
                if (!src) continue;
                if (!consistencyMap.has(src)) consistencyMap.set(src, new Set());
                consistencyMap.get(src).add((s.targetText || '').trim());
            }
        }

        for (const { s, gid } of filteredSegs) {
            _qaPushSegmentRuleFindings(results, s, gid, { checkTerms, checkTags, checkNumbers });

            // 譯文一致性
            if (checkConsistency && consistencyMap) {
                const src = (s.sourceText || '').trim();
                const variants = src ? consistencyMap.get(src) : null;
                if (variants && variants.size > 1) {
                    results.push({ segId: s.id, gid, type: '譯文不一致',
                        info: `此原文有 ${variants.size} 種不同譯文`, key: `${gid}:consistency` });
                }
            }
        }
        return { results, filteredSegs };
    }

    function renderQaResults() {
        const tbody = document.getElementById('qaResultsBody');
        const table = document.getElementById('qaResultsTable');
        const statusEl = document.getElementById('qaStatus');
        if (!tbody || !table || !statusEl) return;

        const hideIgnored = document.getElementById('qaHideIgnored')?.checked;
        const tagCount = _qaResults.filter(r => r.type === 'Tag 檢查').length;
        const tbCount = _qaResults.filter(r => r.type === '術語未套用').length;
        const conCount = _qaResults.filter(r => r.type === '譯文不一致').length;
        const numCount = _qaResults.filter(r => r.type === '數字不相符').length;
        const typoCount = _qaResults.filter(r => (r.type === '錯字' || r.type === '錯字／打字')).length;
        const sortedResults = [..._qaResults].sort((a, b) => {
            const dir = qaSortDir === 'desc' ? -1 : 1;
            if (qaSortKey === 'gid') return ((a.gid || 0) - (b.gid || 0)) * dir;
            const av = String(a[qaSortKey] || '');
            const bv = String(b[qaSortKey] || '');
            return av.localeCompare(bv, 'zh-Hant') * dir;
        });

        if (_qaResults.length === 0) {
            table.style.display = 'none';
            statusEl.textContent = '✓ 無發現問題';
            statusEl.style.color = '#16a34a';
            return;
        }

        statusEl.style.color = '#b45309';
        const parts = [];
        if (tagCount) parts.push(`Tag: ${tagCount}`);
        if (tbCount) parts.push(`術語: ${tbCount}`);
        if (conCount) parts.push(`一致性: ${conCount}`);
        if (numCount) parts.push(`數字: ${numCount}`);
        if (typoCount) parts.push(`錯字: ${typoCount}`);
        statusEl.textContent = `發現 ${_qaResults.length} 個問題（${parts.join('，')}）`;
        table.style.display = '';

        tbody.innerHTML = '';
        for (const r of sortedResults) {
            const isIgnored = _qaIgnoredSet.has(r.key);
            if (hideIgnored && isIgnored) continue;
            const tr = document.createElement('tr');
            tr.className = 'qa-row' + (isIgnored ? ' is-ignored' : '');
            tr.dataset.qaKey = r.key;

            const tdNum = document.createElement('td');
            tdNum.className = 'qa-td-num qa-clickable';
            tdNum.textContent = r.gid;
            tdNum.title = '點擊跳至句段';
            tdNum.addEventListener('click', () => _qaJumpToSegment(r.segId));

            const tdType = document.createElement('td');
            tdType.className = 'qa-td-type';
            tdType.textContent = (r.type === '錯字／打字' || r.type === '錯字/打字') ? '錯字' : r.type;

            const tdInfo = document.createElement('td');
            tdInfo.className = 'qa-td-info qa-clickable';
            tdInfo.textContent = r.info;
            tdInfo.title = '點擊跳至句段';
            tdInfo.addEventListener('click', () => _qaJumpToSegment(r.segId));

            const tdIgnore = document.createElement('td');
            tdIgnore.className = 'qa-td-ignore';
            const cb = document.createElement('input');
            cb.type = 'checkbox';
            cb.checked = isIgnored;
            cb.addEventListener('change', () => {
                if (cb.checked) _qaIgnoredSet.add(r.key); else _qaIgnoredSet.delete(r.key);
                tr.classList.toggle('is-ignored', cb.checked);
                if (document.getElementById('qaHideIgnored')?.checked && cb.checked) {
                    tr.style.display = 'none';
                }
            });
            tdIgnore.appendChild(cb);

            tr.appendChild(tdNum);
            tr.appendChild(tdType);
            tr.appendChild(tdInfo);
            tr.appendChild(tdIgnore);
            tbody.appendChild(tr);
        }
    }

    // QA 折疊檢查項目
    const btnQaCollapse = document.getElementById('btnQaCollapseChecks');
    if (btnQaCollapse) {
        btnQaCollapse.addEventListener('click', () => {
            const body = document.getElementById('qaChecksBody');
            if (!body) return;
            const collapsed = body.style.display === 'none';
            body.style.display = collapsed ? '' : 'none';
            btnQaCollapse.textContent = (collapsed ? '▾' : '▸') + ' 檢查項目';
        });
    }

    // QA 句段範圍核取方塊（啟用/停用輸入框）
    const qaUseRangeCb = document.getElementById('qaUseRange');
    const qaRangeFromEl = document.getElementById('qaRangeFrom');
    const qaRangeToEl = document.getElementById('qaRangeTo');
    const qaScopeCurrentFilteredEl = document.getElementById('qaScopeCurrentFiltered');
    const qaConfigControls = [
        'qaCheckTerms', 'qaCheckTags', 'qaCheckConsistency', 'qaCheckNumbers', 'qaCheckTypos',
        'qaUseRange', 'qaRangeFrom', 'qaRangeTo', 'qaIncludeLocked', 'qaScopeCurrentFiltered'
    ];
    function setQaControlsLocked(locked) {
        qaRunInProgress = !!locked;
        const btnQaCollapseChecks = document.getElementById('btnQaCollapseChecks');
        if (btnQaCollapseChecks) btnQaCollapseChecks.disabled = !!locked;
        qaConfigControls.forEach((id) => {
            const el = document.getElementById(id);
            if (!el) return;
            el.disabled = !!locked;
        });
        const qaChecksBody = document.getElementById('qaChecksBody');
        if (qaChecksBody) qaChecksBody.classList.toggle('qa-controls-locked', !!locked);
        const qaOptionsBar = document.querySelector('.qa-options-bar');
        if (qaOptionsBar) qaOptionsBar.classList.toggle('qa-controls-locked', !!locked);
        if (btnRunQA) btnRunQA.disabled = !!locked;
    }
    function resetQaScopeInputs() {
        if (qaUseRangeCb) qaUseRangeCb.checked = false;
        if (qaRangeFromEl) {
            qaRangeFromEl.value = '';
            qaRangeFromEl.disabled = true;
        }
        if (qaRangeToEl) {
            qaRangeToEl.value = '';
            qaRangeToEl.disabled = true;
        }
        const qaIncludeLockedEl = document.getElementById('qaIncludeLocked');
        if (qaIncludeLockedEl) qaIncludeLockedEl.checked = false;
        if (qaScopeCurrentFilteredEl) qaScopeCurrentFilteredEl.checked = false;
        updateQaScopeFilterLockState(false);
    }
    function getQaScopeVisibleSegIdSet() {
        if (!qaScopeCurrentFilteredEl?.checked) return null;
        if (!gridBody) return null;
        const visibleSegIds = new Set();
        const rows = gridBody.querySelectorAll('.grid-data-row');
        rows.forEach((row) => {
            if (!isGridDataRowFilterVisible(row)) return;
            const sid = parseId(row.dataset.segId);
            if (sid != null) visibleSegIds.add(sid);
        });
        return visibleSegIds;
    }
    /** QA「當時篩選結果」：一行一條，與篩選群組 chip 造句一致 */
    function buildQaFilterConditionsSummaryLines() {
        const lines = [];
        const q = (sfInput?.value || '').trim();
        const scopes = Array.from(document.querySelectorAll('.sf-scope-cb:checked')).map((cb) => cb.value);
        const sj = scopes.map((s) => scopeNames[s] || s).join('、');
        const isInv = !!(btnSfInvert && btnSfInvert.classList.contains('active'));
        if (q) {
            let line = isInv
                ? `不包含字串『${q}』（搜尋範圍：${sj || '—'}）`
                : `包含字串『${q}』（搜尋範圍：${sj || '—'}）`;
            if (sfUseRegexChecked) line += '（正則模式）';
            lines.push(line);
        } else if (isInv) {
            lines.push(`不包含字串（搜尋範圍：${sj || '全部'}）`);
        }
        const adv = readSfAdvancedSpecFromDom();
        if (adv.statuses && adv.statuses.length) {
            lines.push(`句段狀態：${adv.statuses.map((v) => statusNames[v] || v).join('、')}`);
        }
        const tm = String(adv.tmVal || '').trim();
        if (tm) lines.push(`TM%：${tm}`);
        const rowSpec = sfRowSpecFromAdvancedPart(adv);
        if (rowSpec.enabled) {
            const rf = String(adv.rowRangeFrom || '').trim();
            const rt = String(adv.rowRangeTo || '').trim();
            const mode = rowSpec.exclude ? '排除' : '顯示';
            lines.push(`句段範圍：${mode} ${rf || '起'} - ${rt || '訖'}`);
        }
        sfFilterGroups.forEach((g) => {
            getSfFilterGroupConditionLines(g).forEach((ln) => lines.push(ln));
        });
        return lines;
    }

    /** @param {string} line1 主問句 @param {string} line2 括號內補充（可含括號） */
    function confirmQaFilterScopeModal(line1, line2) {
        return new Promise((resolve) => {
            const overlay = document.getElementById('qaFilterScopeConfirmModal');
            const msgEl = document.getElementById('qaFilterScopeConfirmMsg');
            const btnOk = document.getElementById('btnQaFilterScopeConfirmOk');
            const btnCancel = document.getElementById('btnQaFilterScopeConfirmCancel');
            if (!overlay || !msgEl || !btnOk || !btnCancel) {
                openCatConfirmModal(`${line1}\n\n${line2}`).then(resolve);
                return;
            }
            msgEl.innerHTML = '';
            const p1 = document.createElement('p');
            p1.textContent = line1;
            const p2 = document.createElement('p');
            p2.textContent = line2;
            msgEl.appendChild(p1);
            msgEl.appendChild(p2);
            const done = (v) => {
                overlay.classList.add('hidden');
                btnOk.removeEventListener('click', onOk);
                btnCancel.removeEventListener('click', onCancel);
                overlay.removeEventListener('click', onOverlay);
                document.removeEventListener('keydown', onKey);
                resolve(v);
            };
            const onOk = () => done(true);
            const onCancel = () => done(false);
            const onOverlay = (e) => {
                if (e.target === overlay) done(false);
            };
            const onKey = (e) => {
                if (e.key === 'Escape') {
                    e.preventDefault();
                    done(false);
                }
            };
            btnOk.addEventListener('click', onOk);
            btnCancel.addEventListener('click', onCancel);
            overlay.addEventListener('click', onOverlay);
            document.addEventListener('keydown', onKey);
            overlay.classList.remove('hidden');
            btnOk.focus();
        });
    }
    function updateQaSortHeaderState() {
        const headers = document.querySelectorAll('#qaResultsTable .qa-sortable-th');
        headers.forEach((th) => {
            const key = th.dataset.sortKey;
            if (!key) return;
            const active = key === qaSortKey;
            th.setAttribute('aria-sort', active ? (qaSortDir === 'asc' ? 'ascending' : 'descending') : 'none');
            let label = th.textContent.replace(/[↑↓]$/, '').trim();
            if (active) label += qaSortDir === 'asc' ? '↑' : '↓';
            th.textContent = label;
        });
    }
    function renderQaRunSummary(runSummary) {
        const footerDOM = document.getElementById('liveFooterContent');
        if (!footerDOM) return;
        if (!runSummary) {
            footerDOM.innerHTML = '請選取句段以檢視詳細資訊。';
            return;
        }
        footerDOM.innerHTML = runSummary;
    }
    if (qaUseRangeCb) {
        qaUseRangeCb.addEventListener('change', () => {
            const enabled = qaUseRangeCb.checked;
            if (qaRangeFromEl) qaRangeFromEl.disabled = !enabled;
            if (qaRangeToEl) qaRangeToEl.disabled = !enabled;
            if (!enabled) {
                if (qaRangeFromEl) qaRangeFromEl.value = '';
                if (qaRangeToEl) qaRangeToEl.value = '';
            }
        });
    }
    if (qaScopeCurrentFilteredEl) {
        qaScopeCurrentFilteredEl.addEventListener('change', () => updateQaScopeFilterLockState());
    }
    document.querySelectorAll('#qaResultsTable .qa-sortable-th').forEach((th) => {
        th.addEventListener('click', () => {
            const key = th.dataset.sortKey;
            if (!key) return;
            if (qaSortKey === key) qaSortDir = qaSortDir === 'asc' ? 'desc' : 'asc';
            else {
                qaSortKey = key;
                qaSortDir = key === 'gid' ? 'asc' : 'asc';
            }
            updateQaSortHeaderState();
            renderQaResults();
        });
    });
    updateQaSortHeaderState();
    if (qaLastRunSummaryHtml) renderQaRunSummary(qaLastRunSummaryHtml);

    // QA 按鈕事件
    const btnRunQA = document.getElementById('btnRunQA');
    if (btnRunQA) {
        btnRunQA.addEventListener('click', async () => {
            if (qaRunInProgress) return;
            const useRange = document.getElementById('qaUseRange')?.checked ?? false;
            const fromVal = useRange ? document.getElementById('qaRangeFrom')?.value : null;
            const toVal = useRange ? document.getElementById('qaRangeTo')?.value : null;
            const fromIdx = fromVal ? parseInt(fromVal, 10) : null;
            const toIdx = toVal ? parseInt(toVal, 10) : null;
            const includeLocked = document.getElementById('qaIncludeLocked')?.checked ?? false;
            const checkTerms = document.getElementById('qaCheckTerms')?.checked ?? true;
            const checkTags = document.getElementById('qaCheckTags')?.checked ?? true;
            const checkConsistency = document.getElementById('qaCheckConsistency')?.checked ?? true;
            const checkNumbers = document.getElementById('qaCheckNumbers')?.checked ?? true;
            const checkTypos = document.getElementById('qaCheckTypos')?.checked ?? false;
            const statusEl = document.getElementById('qaStatus');
            const allowedSegIds = getQaScopeVisibleSegIdSet();
            const isFilterContext = sfMode === 'filter';
            if (isFilterContext && useRange) {
                const ok = qaScopeCurrentFilteredEl?.checked
                    ? await confirmQaFilterScopeModal(
                        '按照目前設定將不會把隱藏句段列入 QA 範圍，是否確定？',
                        '（如欲納入隱藏句段，請取消勾選「目前篩選結果」後再重試）'
                    )
                    : await confirmQaFilterScopeModal(
                        '按照目前設定將連隱藏句段一起列入 QA 範圍，是否確定？',
                        '（如欲排除隱藏句段，請額外勾選「目前篩選結果」後再重試）'
                    );
                if (!ok) return;
            }
            const runAt = new Date().toLocaleString('zh-TW', { hour12: false });
            const checks = [];
            if (checkTerms) checks.push('術語');
            if (checkTags) checks.push('Tag');
            if (checkConsistency) checks.push('譯文不一致');
            if (checkNumbers) checks.push('數字');
            if (checkTypos) checks.push('錯字（AI）');
            const scopeParts = [includeLocked ? '含鎖定' : '不含鎖定'];
            if (useRange && (fromIdx != null || toIdx != null)) {
                const a = Number.isFinite(fromIdx) ? fromIdx : 1;
                const b = Number.isFinite(toIdx) ? toIdx : '末句';
                scopeParts.push(`句段範圍 ${a} - ${b}`);
            }
            const condLines = buildQaFilterConditionsSummaryLines();
            const condHtml = condLines.length
                ? condLines.map((line) => `<div>${escapeHtml(line)}</div>`).join('')
                : '<div>（無）</div>';
            qaLastRunSummaryHtml = `
                <div><strong>現有 QA 執行摘要</strong></div>
                <div>執行時間：${runAt}</div>
                <div>檢查項目：${checks.length ? checks.join('、') : '（未選擇）'}</div>
                <div>檢查範圍：${scopeParts.join('、')}</div>
                <div>當時篩選結果</div>
                ${condHtml}
            `;
            renderQaRunSummary(qaLastRunSummaryHtml);

            setQaControlsLocked(true);
            try {
                const { results, filteredSegs } = runQaChecks(currentSegmentsList, {
                    fromIdx, toIdx, includeLocked, allowedSegIds, checkTerms, checkTags, checkConsistency, checkNumbers
                });
                _qaResults = results;

                if (checkTypos) {
                    if (statusEl) {
                        statusEl.textContent = '執行本地檢查完成，錯字檢查（AI）進行中…';
                        statusEl.style.color = '#64748b';
                    }
                    const settings = await DBService.getAiSettings();
                    if (!settings?.apiKey && settings?.preferOpenAiProxy === false) {
                        alert('已勾選「錯字（由 AI 檢查）」，但無法連線 AI。請至「AI 管理」設定。');
                    } else if (typeof window.CatAiTranslate?.qaChineseTypos !== 'function') {
                        alert('AI 模組未載入，無法執行錯字檢查。');
                    } else {
                        const typoItems = filteredSegs.map(({ s, gid }) => ({
                            segId: s.id,
                            gid,
                            targetText: s.targetText || ''
                        }));
                        const typoOut = await window.CatAiTranslate.qaChineseTypos(typoItems, settings);
                        if (typoOut.error) {
                            alert(typoOut.error);
                        } else {
                            for (const it of typoOut.issues) {
                                _qaResults.push({
                                    segId: it.segId,
                                    gid: it.gid,
                                    type: '錯字',
                                    info: it.detail,
                                    key: `${it.gid}:typo`
                                });
                            }
                        }
                    }
                }

                renderQaResults();
            } finally {
                setQaControlsLocked(false);
                resetQaScopeInputs();
            }
        });
    }
    document.getElementById('qaHideIgnored')?.addEventListener('change', renderQaResults);

    // ── TM Concordance Search ────────────────────────────────────────────────

    function parseTmConcordanceQuery(raw) {
        const phrases = [];
        const tokens = [];
        const s = String(raw || '');
        let i = 0;
        while (i < s.length) {
            const ch = s[i];
            if (ch === '"') {
                const end = s.indexOf('"', i + 1);
                if (end === -1) {
                    const tail = s.slice(i + 1).trim();
                    if (tail) tail.split(/\s+/).forEach(t => { if (t) tokens.push(t); });
                    break;
                }
                const inner = s.slice(i + 1, end);
                if (inner) phrases.push(inner);
                i = end + 1;
            } else if (/\s/.test(ch)) {
                i++;
            } else {
                const start = i;
                while (i < s.length && s[i] !== '"' && !/\s/.test(s[i])) i++;
                const word = s.slice(start, i);
                if (word) tokens.push(word);
            }
        }
        return { phrases, tokens };
    }

    function tmConcordanceMatchesQuery(text, phrases, tokens) {
        const lower = (text || '').toLowerCase();
        for (const p of phrases) {
            if (p == null || p === '') continue;
            if (!lower.includes(String(p).toLowerCase())) return false;
        }
        for (const t of tokens) {
            if (t == null || t === '') continue;
            if (!lower.includes(String(t).toLowerCase())) return false;
        }
        return true;
    }

    function buildTmConcordanceHighlightedHtml(rawText, phrases, tokens) {
        const text = rawText == null ? '' : String(rawText);
        const terms = [];
        phrases.forEach(p => { if (p != null && p !== '') terms.push(String(p)); });
        tokens.forEach(t => { if (t != null && t !== '') terms.push(String(t)); });
        if (!terms.length) return text.replace(/</g, '&lt;').replace(/>/g, '&gt;');
        const lower = text.toLowerCase();
        const intervals = [];
        for (const term of terms) {
            const tl = term.toLowerCase();
            let pos = 0;
            let idx;
            while ((idx = lower.indexOf(tl, pos)) !== -1) {
                intervals.push([idx, idx + term.length]);
                pos = idx + 1;
            }
        }
        if (!intervals.length) return text.replace(/</g, '&lt;').replace(/>/g, '&gt;');
        intervals.sort((a, b) => a[0] - b[0]);
        const merged = [];
        for (const iv of intervals) {
            if (!merged.length || iv[0] > merged[merged.length - 1][1]) merged.push([iv[0], iv[1]]);
            else merged[merged.length - 1][1] = Math.max(merged[merged.length - 1][1], iv[1]);
        }
        let out = '';
        let last = 0;
        for (const [a, b] of merged) {
            out += text.slice(last, a).replace(/</g, '&lt;').replace(/>/g, '&gt;');
            out += '<mark class="tm-search-hit">' + text.slice(a, b).replace(/</g, '&lt;').replace(/>/g, '&gt;') + '</mark>';
            last = b;
        }
        out += text.slice(last).replace(/</g, '&lt;').replace(/>/g, '&gt;');
        return out;
    }

    function tmConcordanceKeyFieldText(seg) {
        if (!seg || !Array.isArray(seg.keys) || !seg.keys.length) return '';
        return seg.keys.map((k) => (k == null ? '' : String(k))).join('\n');
    }

    function renderConcordanceFooter(m) {
        const footerDOM = document.getElementById('liveFooterContent');
        if (!footerDOM) return;
        if (!m) { footerDOM.innerHTML = '請選取句段以檢視詳細資訊。'; return; }
        const esc = (s) => String(s ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
        const keyText = m.key || tmConcordanceKeyFieldText(m);
        const createdAt = m.createdAt ? new Date(m.createdAt).toLocaleString('zh-TW', { hour12: false }) : '';
        footerDOM.innerHTML = `<div class="cat-footer-block-wrap">
            <div class="cat-footer-section cat-footer-tm-meta">
                <div><strong>TM 名稱：</strong>${esc(m.tmName || 'N/A')}</div>
                ${keyText ? `<div><strong>Key：</strong>${esc(keyText)}</div>` : ''}
                ${m.writtenFile ? `<div><strong>寫入檔案：</strong>${esc(m.writtenFile)}</div>` : ''}
                ${m.createdBy ? `<div><strong>建立者：</strong>${esc(m.createdBy)}</div>` : ''}
                ${createdAt ? `<div><strong>建立時間：</strong>${esc(createdAt)}</div>` : ''}
            </div>
            ${(m.prevSegment || m.nextSegment) ? `<div class="cat-footer-section cat-footer-context">
                <div class="cat-footer-context-inner">
                    <div><strong>上一句</strong><br>${esc(m.prevSegment || '')}</div>
                    <div><strong>下一句</strong><br>${esc(m.nextSegment || '')}</div>
                </div>
            </div>` : ''}
        </div>`;
    }

    function runTmConcordanceSearch() {
        const input = document.getElementById('tmSearchInput');
        const fieldSel = document.getElementById('tmSearchField');
        const resultsEl = document.getElementById('tmSearchConcordanceResults');
        if (!input || !resultsEl) return;
        window.updateTmConcordanceSelection = null;
        const raw = (input.value || '').trim();
        window.currentTmConcordanceMatches = [];
        window.tmConcordanceSelectedIndex = 0;
        if (!raw) { resultsEl.innerHTML = '<div style="color:#64748b; padding:0.5rem;">請輸入搜尋關鍵字。</div>'; return; }
        const { phrases, tokens } = parseTmConcordanceQuery(raw);
        if (!phrases.length && !tokens.length) {
            resultsEl.innerHTML = '<div style="color:#64748b; padding:0.5rem;">請輸入有效的搜尋關鍵字。</div>';
            return;
        }
        const field = fieldSel ? fieldSel.value : 'source';
        const cache = window.ActiveTmCache || [];
        const matches = [];
        cache.forEach(seg => {
            const text = field === 'key'
                ? tmConcordanceKeyFieldText(seg)
                : (field === 'target' ? (seg.targetText || '') : (seg.sourceText || ''));
            if (tmConcordanceMatchesQuery(text, phrases, tokens)) matches.push(seg);
        });
        if (!matches.length) {
            resultsEl.innerHTML = '<div style="color:#64748b; padding:0.5rem;">沒有找到相符的 TM 記錄。</div>';
            return;
        }
        const maxShow = 50;
        const shown = matches.slice(0, maxShow);
        window.currentTmConcordanceMatches = shown;
        window.tmConcordanceSelectedIndex = 0;
        resultsEl.innerHTML = shown.map((m, i) => {
            const src = buildTmConcordanceHighlightedHtml(m.sourceText || '', phrases, tokens);
            const tgt = buildTmConcordanceHighlightedHtml(m.targetText || '', phrases, tokens);
            const keyHtml = buildTmConcordanceHighlightedHtml(tmConcordanceKeyFieldText(m), phrases, tokens);
            const keyRow = field === 'key' ? `<div style="margin-bottom:2px;"><b>Key：</b>${keyHtml}</div>` : '';
            const tmLabel = (m.tmName || '').replace(/</g, '&lt;');
            return `<div class="tm-concordance-item${i === 0 ? ' tm-concordance-item--selected' : ''}" data-idx="${i}" title="單擊選取；雙擊套用譯文">
                <div style="font-size:0.78rem; color:#64748b; margin-bottom:2px;"><strong>${i + 1}</strong> · ${tmLabel}</div>
                ${keyRow}
                <div style="margin-bottom:2px;"><b>原：</b>${src}</div>
                <div><b>譯：</b>${tgt}</div>
            </div>`;
        }).join('') + (matches.length > maxShow ? `<div style="padding:0.4rem; color:#94a3b8; font-size:0.8rem;">僅顯示前 ${maxShow} 筆（共 ${matches.length} 筆相符）</div>` : '');

        const updateConcordanceSelection = () => {
            resultsEl.querySelectorAll('.tm-concordance-item').forEach((item, i) => {
                item.classList.toggle('tm-concordance-item--selected', i === window.tmConcordanceSelectedIndex);
            });
            const m = (window.currentTmConcordanceMatches || [])[window.tmConcordanceSelectedIndex];
            renderConcordanceFooter(m || null);
        };
        window.updateTmConcordanceSelection = updateConcordanceSelection;
        renderConcordanceFooter(shown[0] || null);
        resultsEl.querySelectorAll('.tm-concordance-item').forEach(item => {
            item.addEventListener('click', () => {
                const idx = parseInt(item.getAttribute('data-idx'));
                if (!Number.isFinite(idx)) return;
                window.tmConcordanceSelectedIndex = idx;
                updateConcordanceSelection();
            });
            item.addEventListener('dblclick', () => {
                const idx = parseInt(item.getAttribute('data-idx'));
                if (Number.isFinite(idx)) window.applyTmConcordanceAtIndex(idx);
            });
        });
    }

    window.applyTmConcordanceAtIndex = function(index, fromKeyboard = false) {
        const matches = window.currentTmConcordanceMatches;
        if (!matches || index < 0 || index >= matches.length) return;
        const m = matches[index];
        window.tmConcordanceSelectedIndex = index;
        const el = document.querySelector(`#tmSearchConcordanceResults .tm-concordance-item[data-idx="${index}"]`);
        if (el) {
            el.closest('#tmSearchConcordanceResults')?.querySelectorAll('.tm-concordance-item').forEach((item, i) => {
                item.classList.toggle('tm-concordance-item--selected', i === index);
            });
        }
        window.handleCatResultApply(el || document.body, 'TM', m.targetText || '', undefined, index, fromKeyboard);
    };

    const btnTmSearch = document.getElementById('btnTmSearch');
    if (btnTmSearch) btnTmSearch.addEventListener('click', runTmConcordanceSearch);
    const tmSearchInputEl = document.getElementById('tmSearchInput');
